use aiken/collection/list
use cardano/transaction.{InlineDatum, Output, Transaction}

pub type EscrowDatum {
  beneficiary: ByteArray,
  amount: Int,
}

fn check_output_datum(output: Output, tx: Transaction) -> Bool {
  when output.datum is {
    InlineDatum(raw) -> {
      expect typed: EscrowDatum = raw
      list.has(tx.extra_signatories, typed.beneficiary)
    }
    _ -> False
  }
}

validator escrow_release {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _input: Data,
    tx: Transaction,
  ) {
    expect Some(d) = datum
    let Transaction { extra_signatories, outputs, .. } = tx
    let beneficiary_signed = list.has(extra_signatories, d.beneficiary)
    let output_valid =
      list.any(outputs, fn(output) { check_output_datum(output, tx) })
    beneficiary_signed && output_valid
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type SpendDatum {
  min_price: Int,
  owner: ByteArray,
}

pub type OracleDatum {
  price: Int,
}

pub type SpendRedeemer {
  Spend
}

fn find_oracle_price(ref_inputs: List<Output>) -> Option<Int> {
  let oracle_output =
    list.find(
      ref_inputs,
      fn(o) {
        when o.datum is {
          InlineDatum(_) -> True
          _ -> False
        }
      },
    )
  when oracle_output is {
    Some(o) ->
      when o.datum is {
        InlineDatum(raw) -> {
          expect oracle: OracleDatum = raw
          Some(oracle.price)
        }
        _ -> None
      }
    None -> None
  }
}

validator price_feed_validator {
  spend(
    datum: Option<SpendDatum>,
    _redeemer: SpendRedeemer,
    _own_ref: OutputReference,
    tx: Transaction,
  ) {
    expect Some(d) = datum

    let Transaction { reference_inputs, extra_signatories, .. } = tx

    let ref_outputs = list.map(reference_inputs, fn(i) { i.output })

    let oracle_price_opt = find_oracle_price(ref_outputs)

    when oracle_price_opt is {
      Some(price) -> {
        let price_ok = price >= d.min_price
        let signed = list.has(extra_signatories, d.owner)
        price_ok && signed
      }
      None -> False
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{Transaction}

pub type MultiSigDatum {
  required_signers: List<ByteArray>,
  threshold: Int,
}

fn count_signers(
  required: List<ByteArray>,
  signatories: List<ByteArray>,
) -> Int {
  list.foldl(
    required,
    0,
    fn(signer, acc) {
      if list.has(signatories, signer) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator multisig_wallet {
  spend(
    datum: Option<MultiSigDatum>,
    _redeemer: Data,
    _output_reference: Data,
    tx: Transaction,
  ) {
    expect Some(d) = datum
    let signed_count = count_signers(d.required_signers, tx.extra_signatories)
    signed_count >= d.threshold
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{InlineDatum, Output, Transaction}

pub type LoanDatum {
  borrower: ByteArray,
  principal: Int,
  interest: Int,
  due_date: Int,
}

fn get_total_repayment(datum: LoanDatum) -> Int {
  datum.principal + datum.interest
}

fn borrower_signed(tx: Transaction, borrower: ByteArray) -> Bool {
  list.any(tx.extra_signatories, fn(sig) { sig == borrower })
}

fn sum_outputs_to_borrower(outputs: List<Output>, borrower: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(output, acc) {
      when output.datum is {
        InlineDatum(raw) -> {
          expect typed: LoanDatum = raw
          if typed.borrower == borrower {
            let lovelace =
              output.value
                |> fn(v) {
                    list.foldl(
                      v |> fn(_) { [] },
                      0,
                      fn(_, a) { a },
                    )
                  }
            acc + lovelace
          } else {
            acc
          }
        }
        _ -> acc
      }
    },
  )
}

validator loan_repay {
  spend(
    datum: Option<LoanDatum>,
    _redeemer: Data,
    _own_ref: Data,
    tx: Transaction,
  ) {
    expect Some(loan) = datum

    let total_due = get_total_repayment(loan)

    let signed = borrower_signed(tx, loan.borrower)

    let paid =
      list.any(
        tx.outputs,
        fn(output) {
          let ada_amount =
            when
              list.find(
                output.value |> fn(_) { [] },
                fn(_) { True },
              )
            is {
              Some(_) -> 0
              None -> 0
            }
          ada_amount >= total_due
        },
      )

    let _ = paid

    signed && total_due > 0
  }

  else(_) {
    fail
  }
}

