validator treasury_spend {
  spend(
    datum: Option<ProposalDatum>,
    _redeemer: Data,
    _input: Data,
    tx: Transaction,
  ) {
    when datum is {
      Some(proposal) -> proposal.votes_for > proposal.votes_against
      None -> {
        let found =
          list.any(
            tx.outputs,
            fn(output) {
              when get_proposal_datum(output) is {
                Some(proposal) -> proposal.votes_for > proposal.votes_against
                None -> False
              }
            },
          )
        found
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{InlineDatum, Output, Transaction}

pub type CollateralDatum {
  borrower: ByteArray,
  loan_ref: ByteArray,
  liquidation_ratio: Int,
}

pub type CollateralRedeemer {
  Repay
  Liquidate { is_default: Bool }
}

fn check_borrower_signed(tx: Transaction, borrower: ByteArray) -> Bool {
  list.any(tx.extra_signatories, fn(sig) { sig == borrower })
}

fn find_output_with_loan_ref(
  outputs: List<Output>,
  loan_ref: ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      when output.datum is {
        InlineDatum(raw) -> {
          expect d: CollateralDatum = raw
          d.loan_ref == loan_ref
        }
        _ -> False
      }
    },
  )
}

validator collateral_vault {
  spend(
    datum: Option<CollateralDatum>,
    redeemer: CollateralRedeemer,
    _output_reference: Data,
    tx: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Repay -> check_borrower_signed(tx, d.borrower)
      Liquidate { is_default } -> {
        let borrower_signed = check_borrower_signed(tx, d.borrower)
        let loan_in_default = is_default
        let valid_liquidation_ratio = d.liquidation_ratio > 0
        let loan_ref_present =
          find_output_with_loan_ref(tx.outputs, d.loan_ref)
        valid_liquidation_ratio && loan_ref_present && (
          borrower_signed || loan_in_default
        )
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{InlineDatum, Output, Transaction}

pub type EscrowDatum {
  seller: ByteArray,
  buyer: ByteArray,
  amount: Int,
  deadline: Int,
}

fn find_output_with_datum(outputs: List<Output>, datum: EscrowDatum) -> Bool {
  list.any(
    outputs,
    fn(output) {
      when output.datum is {
        InlineDatum(raw) -> {
          expect typed: EscrowDatum = raw
          typed.seller == datum.seller && typed.buyer == datum.buyer && typed.amount == datum.amount && typed.deadline == datum.deadline
        }
        _ -> False
      }
    },
  )
}

validator safe_escrow {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _input: Data,
    tx: Transaction,
  ) {
    when datum is {
      Some(d) -> {
        let Transaction { outputs, .. } = tx
        find_output_with_datum(outputs, d)
      }
      None -> fail @"No inline datum found: rejecting spend"
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{InlineDatum, Input, Output, Transaction}

pub type BridgeDatum {
  amount: Int,
  recipient: ByteArray,
  nonce: ByteArray,
}

pub type NonceDatum {
  used_nonces: List<ByteArray>,
}

fn find_bridge_datum(output: Output) -> Option<BridgeDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect typed: BridgeDatum = raw
      Some(typed)
    }
    _ -> None
  }
}

fn find_nonce_datum(input: Input) -> Option<NonceDatum> {
  when input.output.datum is {
    InlineDatum(raw) -> {
      expect typed: NonceDatum = raw
      Some(typed)
    }
    _ -> None
  }
}

fn nonce_not_used(
  reference_inputs: List<Input>,
  nonce: ByteArray,
) -> Bool {
  let nonce_records =
    list.filter_map(reference_inputs, fn(inp) { find_nonce_datum(inp) })
  when nonce_records is {
    [] -> False
    _ ->
      list.all(
        nonce_records,
        fn(nd) { !list.has(nd.used_nonces, nonce) },
      )
  }
}

fn verify_recipient_signs(
  tx: Transaction,
  recipient: ByteArray,
) -> Bool {
  list.has(tx.extra_signatories, recipient)
}

validator bridge_release {
  spend(
    datum: Option<BridgeDatum>,
    _redeemer: Data,
    _output_reference: Data,
    tx: Transaction,
  ) {
    expect Some(bridge) = datum

    let nonce_valid =
      nonce_not_used(tx.reference_inputs, bridge.nonce)

    let recipient_signed =
      verify_recipient_signs(tx, bridge.recipient)

    let amount_positive = bridge.amount > 0

    nonce_valid && recipient_signed && amount_positive
  }

  else(_) {
    False
  }
}

