use aiken/collection/list
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type VersionedDatum {
  version: Int,
  admin: ByteArray,
  params: Int,
}

pub type UpgradeableRedeemer {
  Upgrade { new_version: Int, new_params: Int }
  Use
}

fn find_input(
  inputs: List<Input>,
  output_ref: OutputReference,
) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == output_ref })
}

fn find_own_output(outputs: List<Output>, own_input: Input) -> Option<Output> {
  list.find(
    outputs,
    fn(o) { o.address == own_input.output.address },
  )
}

fn get_versioned_datum(output: Output) -> Option<VersionedDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect typed: VersionedDatum = raw
      Some(typed)
    }
    _ -> None
  }
}

fn is_signed_by(
  extra_signatories: List<Hash<Blake2b_224, VerificationKey>>,
  signer: ByteArray,
) -> Bool {
  list.any(extra_signatories, fn(sig) { sig == signer })
}

validator upgradeable {
  spend(
    datum: Option<VersionedDatum>,
    redeemer: UpgradeableRedeemer,
    own_ref: OutputReference,
    tx: Transaction,
  ) {
    expect Some(current_datum) = datum

    when redeemer is {
      Upgrade { new_version, new_params } -> {
        let admin_signed =
          is_signed_by(tx.extra_signatories, current_datum.admin)

        let version_bumped = new_version == current_datum.version + 1

        let own_input_opt = find_input(tx.inputs, own_ref)
        expect Some(own_input) = own_input_opt

        let own_output_opt = find_own_output(tx.outputs, own_input)
        expect Some(own_output) = own_output_opt

        let output_datum_opt = get_versioned_datum(own_output)
        expect Some(output_datum) = output_datum_opt

        let datum_correct =
          output_datum.version == new_version && output_datum.admin == current_datum.admin && output_datum.params == new_params

        let value_preserved =
          own_output.value == own_input.output.value

        admin_signed && version_bumped && datum_correct && value_preserved
      }

      Use -> True
    }
  }

  else(_) {
    fail
  }
}

