use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type OracleDatum {
  price: Int,
  timestamp: Int,
  source: ByteArray,
}

pub type SpendDatum {
  min_price: Int,
  oracle_policy_id: ByteArray,
  oracle_asset_name: ByteArray,
}

validator oracle_consumer {
  spend(
    datum: Option<SpendDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(spend_datum) = datum

    let oracle_price =
      list.foldr(
        self.reference_inputs,
        None,
        fn(input: Input, acc: Option<Int>) {
          when acc is {
            Some(_) -> acc
            None -> {
              let has_oracle_token =
                assets.quantity_of(
                  input.output.value,
                  spend_datum.oracle_policy_id,
                  spend_datum.oracle_asset_name,
                ) > 0
              if has_oracle_token {
                when input.output.datum is {
                  InlineDatum(raw) -> {
                    expect oracle_datum: OracleDatum = raw
                    Some(oracle_datum.price)
                  }
                  _ -> None
                }
              } else {
                None
              }
            }
          }
        },
      )

    when oracle_price is {
      Some(price) -> price >= spend_datum.min_price
      None -> False
    }
  }

  else(_) {
    fail
  }
}

