use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type AuctionDatum {
  highest_bid: Int,
  bidder: ByteArray,
  deadline: Int,
}

pub type AuctionRedeemer {
  new_bid: Int,
  new_bidder: ByteArray,
}

validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: AuctionRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current_datum) = datum

    let deadline_not_passed =
      interval.is_entirely_before(self.validity_range, current_datum.deadline)

    let bid_exceeds_current = redeemer.new_bid > current_datum.highest_bid

    let own_input =
      list.find(self.inputs, fn(input) { input.output_reference == utxo })

    expect Some(my_input) = own_input

    let own_address = my_input.output.address

    let continuing_output_valid =
      list.any(
        self.outputs,
        fn(output) {
          when output.datum is {
            InlineDatum(raw) -> {
              expect new_datum: AuctionDatum = raw
              let bid_matches = new_datum.highest_bid == redeemer.new_bid
              let bidder_matches = new_datum.bidder == redeemer.new_bidder
              let deadline_preserved =
                new_datum.deadline == current_datum.deadline
              let address_matches = output.address == own_address
              let value_sufficient =
                assets.lovelace_of(output.value) >= redeemer.new_bid
              bid_matches && bidder_matches && deadline_preserved && address_matches && value_sufficient
            }
            _ -> False
          }
        },
      )

    deadline_not_passed && bid_exceeds_current && continuing_output_valid
  }

  else(_) {
    fail
  }
}

