use cardano/transaction.{Transaction, Output, OutputReference, InlineDatum}
use aiken/collection/list

pub type ConfigDatum {
  admin: ByteArray,
  fee_bps: Int,
  paused: Bool,
}

pub type ConfigRedeemer {
  UpdateFee { new_fee_bps: Int }
  UpdateAdmin { new_admin: ByteArray }
  Pause
  Unpause
  CloseConfig
}

fn valid_fee_bps(fee: Int) -> Bool {
  fee >= 0 && fee <= 10000
}

fn apply_redeemer(datum: ConfigDatum, redeemer: ConfigRedeemer) -> Bool {
  when redeemer is {
    UpdateFee { new_fee_bps } ->
      valid_fee_bps(new_fee_bps)
    UpdateAdmin { new_admin } ->
      (new_admin != #"")
    Pause ->
      !datum.paused
    Unpause ->
      datum.paused
    CloseConfig ->
      True
  }
}

fn find_continuing_output(outputs: List<Output>, datum: ConfigDatum, redeemer: ConfigRedeemer) -> Bool {
  when redeemer is {
    CloseConfig -> True
    UpdateFee { new_fee_bps } ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: ConfigDatum = raw
            new_datum.admin == datum.admin &&
            new_datum.fee_bps == new_fee_bps &&
            new_datum.paused == datum.paused
          }
          _ -> False
        }
      })
    UpdateAdmin { new_admin } ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: ConfigDatum = raw
            new_datum.admin == new_admin &&
            new_datum.fee_bps == datum.fee_bps &&
            new_datum.paused == datum.paused
          }
          _ -> False
        }
      })
    Pause ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: ConfigDatum = raw
            new_datum.admin == datum.admin &&
            new_datum.fee_bps == datum.fee_bps &&
            new_datum.paused == True
          }
          _ -> False
        }
      })
    Unpause ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: ConfigDatum = raw
            new_datum.admin == datum.admin &&
            new_datum.fee_bps == datum.fee_bps &&
            new_datum.paused == False
          }
          _ -> False
        }
      })
  }
}

validator protocol_config {
  spend(datum: Option<ConfigDatum>, redeemer: ConfigRedeemer, _utxo: OutputReference, self: Transaction) {
    expect Some(d) = datum

    let admin_signed = list.has(self.extra_signatories, d.admin)

    let not_paused_or_unpausing =
      when redeemer is {
        Unpause -> True
        CloseConfig -> True
        _ -> !d.paused
      }

    let redeemer_valid = apply_redeemer(d, redeemer)

    let output_valid = find_continuing_output(self.outputs, d, redeemer)

    admin_signed && not_paused_or_unpausing && redeemer_valid && output_valid
  }

  else(_) {
    False
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Output, Transaction}
use cardano/transaction.{OutputReference}

pub type PoolDatum {
  reserve_a: Int,
  reserve_b: Int,
  lp_supply: Int,
}

pub type WithdrawRedeemer {
  lp_burn_amount: Int,
  min_a_out: Int,
  min_b_out: Int,
}

fn find_pool_output(outputs: List<Output>, pool_policy: ByteArray) -> Option<Output> {
  list.find(
    outputs,
    fn(o) { assets.quantity_of(o.value, pool_policy, "pool") > 0 },
  )
}

validator lp_withdraw(
  pool_policy: ByteArray,
  lp_policy: ByteArray,
  lp_asset_name: ByteArray,
) {
  spend(
    datum: Option<PoolDatum>,
    redeemer: WithdrawRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let lp_burn_amount = redeemer.lp_burn_amount
    let min_a_out = redeemer.min_a_out
    let min_b_out = redeemer.min_b_out

    // lp_burn_amount must be positive
    let burn_positive = lp_burn_amount > 0

    // lp_supply must be positive
    let supply_positive = d.lp_supply > 0

    // Calculate proportional shares
    // out_a = reserve_a * lp_burn_amount / lp_supply
    // out_b = reserve_b * lp_burn_amount / lp_supply
    let out_a = d.reserve_a * lp_burn_amount / d.lp_supply
    let out_b = d.reserve_b * lp_burn_amount / d.lp_supply

    // Ensure outputs meet minimum requirements
    let slippage_ok = out_a >= min_a_out && out_b >= min_b_out

    // Check that LP tokens are burned (negative mint)
    let burned = assets.quantity_of(self.mint, lp_policy, lp_asset_name)
    let burn_matches = burned == -lp_burn_amount

    // Verify the pool output has updated reserves
    let pool_output_valid =
      when find_pool_output(self.outputs, pool_policy) is {
        Some(pool_out) ->
          when pool_out.datum is {
            InlineDatum(raw) -> {
              expect new_pool: PoolDatum = raw
              let expected_reserve_a = d.reserve_a - out_a
              let expected_reserve_b = d.reserve_b - out_b
              let expected_lp_supply = d.lp_supply - lp_burn_amount
              new_pool.reserve_a == expected_reserve_a && new_pool.reserve_b == expected_reserve_b && new_pool.lp_supply == expected_lp_supply && new_pool.reserve_a >= 0 && new_pool.reserve_b >= 0 && new_pool.lp_supply >= 0
            }
            _ -> False
          }
        None -> False
      }

    burn_positive && supply_positive && slippage_ok && burn_matches && pool_output_valid
  }

  else(_) {
    fail
  }
}

