use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type SubDatum {
  subscriber: ByteArray,
  expiry: Int,
  fee_per_period: Int,
}

pub type SubRedeemer {
  Renew { new_expiry: Int }
  Cancel
}

fn find_output_with_datum(
  outputs: List<Output>,
  subscriber: ByteArray,
) -> Option<Output> {
  list.find(
    outputs,
    fn(o) {
      when o.datum is {
        InlineDatum(raw) -> {
          expect d: SubDatum = raw
          d.subscriber == subscriber
        }
        _ -> False
      }
    },
  )
}

validator subscription {
  spend(
    datum: Option<SubDatum>,
    redeemer: SubRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Renew { new_expiry } -> {
        let signed_by_subscriber =
          list.has(self.extra_signatories, d.subscriber)
        let valid_new_expiry = new_expiry > d.expiry
        let output_opt = find_output_with_datum(self.outputs, d.subscriber)
        when output_opt is {
          Some(output) -> {
            let fee_paid =
              assets.lovelace_of(output.value) >= d.fee_per_period
            let correct_datum =
              when output.datum is {
                InlineDatum(raw) -> {
                  expect new_d: SubDatum = raw
                  new_d.subscriber == d.subscriber && new_d.expiry == new_expiry && new_d.fee_per_period == d.fee_per_period
                }
                _ -> False
              }
            signed_by_subscriber && valid_new_expiry && fee_paid && correct_datum
          }
          None -> False
        }
      }
      Cancel -> {
        let expired =
          interval.is_entirely_after(self.validity_range, d.expiry)
        let signed_by_subscriber =
          list.has(self.extra_signatories, d.subscriber)
        expired || signed_by_subscriber && interval.is_entirely_after(
          self.validity_range,
          d.expiry,
        )
      }
    }
  }
}

