  recipient: ByteArray,
  nonce: ByteArray,
}

pub type NonceDatum {
  used_nonces: List<ByteArray>,
}

fn find_bridge_datum(datum: Option<BridgeDatum>) -> BridgeDatum {
  expect Some(d) = datum
  d
}

fn check_nonce_unused(
  reference_inputs: List<Input>,
  nonce: ByteArray,
) -> Bool {
  list.any(
    reference_inputs,
    fn(ref_input) {
      when ref_input.output.datum is {
        InlineDatum(raw) -> {
          expect nonce_datum: NonceDatum = raw
          !list.has(nonce_datum.used_nonces, nonce)
        }
        _ -> False
      }
    },
  )
}

fn check_recipient_receives(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      when output.datum is {
        InlineDatum(raw) -> {
          expect _: Data = raw
          let lovelace = assets.lovelace_of(output.value)
          lovelace >= amount
        }
        _ -> {
          let lovelace = assets.lovelace_of(output.value)
          lovelace >= amount
        }
      }
    },
  )
}

fn output_goes_to_recipient(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      let lovelace = assets.lovelace_of(output.value)
      when output.datum is {
        InlineDatum(raw) -> {
          expect typed: BridgeDatum = raw
          typed.recipient == recipient && lovelace >= amount
        }
        _ -> lovelace >= amount
      }
    },
  )
}

validator bridge_release {
  spend(
    datum: Option<BridgeDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    let bridge = find_bridge_datum(datum)

    let nonce_unused =
      check_nonce_unused(self.reference_inputs, bridge.nonce)

    let recipient_signed =
      list.has(self.extra_signatories, bridge.recipient)

    let sufficient_output =
      list.any(
        self.outputs,
        fn(output) {
          assets.lovelace_of(output.value) >= bridge.amount
        },
      )

    nonce_unused && recipient_signed && sufficient_output
  }

  else(_) {
    fail
  }
}

