fn find_output_with_inline_datum(
  outputs: List<Output>,
  datum: VersionedDatum,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.datum is {
        InlineDatum(raw) -> {
          expect typed: VersionedDatum = raw
          typed.version == datum.version && typed.admin == datum.admin && typed.params == datum.params
        }
        _ -> False
      }
    },
  )
}

validator upgradeable {
  spend(
    datum: Option<VersionedDatum>,
    redeemer: UpgradeableRedeemer,
    _utxo: OutputReference,
