    expect Some(d) = datum
    when redeemer is {
      Upgrade { new_version, new_params } -> {
        let admin_signed = list.has(self.extra_signatories, d.admin)
        let version_bumped = new_version > d.version
        let new_datum =
          VersionedDatum {
            version: new_version,
            admin: d.admin,
            params: new_params,
          }
        let output_ok = find_output_with_inline_datum(self.outputs, new_datum)
        admin_signed && version_bumped && output_ok
      }
      Use -> True
    }
  }

  else(_) {
    fail
  }
}

