  owner: ByteArray,
  start_time: Int,
  end_time: Int,
  amount: Int,
}

fn vested_amount(datum: VestingDatum, current_time: Int) -> Int {
  if current_time <= datum.start_time {
    0
  } else if current_time >= datum.end_time {
    datum.amount
  } else {
    let elapsed = current_time - datum.start_time
    let total_duration = datum.end_time - datum.start_time
    datum.amount * elapsed / total_duration
  }
}

validator vesting_linear {
