validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current) = datum

    let deadline_not_passed =
      interval.is_entirely_before(self.validity_range, current.deadline)

    expect Some(cont_out) =
      list.find(
        self.outputs,
        fn(o) {
          when o.datum is {
            InlineDatum(raw) -> {
              expect typed: AuctionDatum = raw
              typed.deadline == current.deadline
            }
            _ -> False
          }
        },
      )

    expect InlineDatum(raw) = cont_out.datum
    expect new_datum: AuctionDatum = raw

    let bid_exceeds = new_datum.highest_bid > current.highest_bid

    let bidder_signed =
      list.has(self.extra_signatories, new_datum.bidder)

    let value_covers_bid =
      assets.lovelace_of(cont_out.value) >= new_datum.highest_bid

    deadline_not_passed && bid_exceeds && bidder_signed && value_covers_bid
  }

  else(_) {
    False
  }
}

