pub type LoanDatum {
  borrower: ByteArray,
  principal: Int,
  interest: Int,
  due_date: Int,
}

fn total_repayment(datum: LoanDatum) -> Int {
  datum.principal + datum.interest
}

fn borrower_signed(self: Transaction, borrower: ByteArray) -> Bool {
  list.has(self.extra_signatories, borrower)
}

fn sufficient_payment(self: Transaction, required: Int) -> Bool {
  let total_paid =
    list.foldl(
      self.outputs,
      0,
      fn(output, acc) { acc + assets.lovelace_of(output.value) },
    )
  total_paid >= required
}

validator loan_repay {
  spend(
    datum: Option<LoanDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let required = total_repayment(d)
    let signed = borrower_signed(self, d.borrower)
    let paid = sufficient_payment(self, required)
    let on_time = interval.is_entirely_before(self.validity_range, d.due_date)
    signed && paid && on_time
  }
}

