pub type CollateralDatum {
  borrower: ByteArray,
  loan_ref: ByteArray,
  liquidation_ratio: Int,
}

pub type CollateralRedeemer {
  Repay
  Liquidate
}

fn find_own_input(
  inputs: List<transaction.Input>,
  utxo: OutputReference,
) -> Option<Output> {
  when inputs is {
    [] -> None
    [input, ..rest] ->
      if input.output_reference == utxo {
        Some(input.output)
      } else {
        find_own_input(rest, utxo)
      }
  }
}

fn is_in_default(liquidation_ratio: Int) -> Bool {
  liquidation_ratio <= 0
}

validator collateral_vault {
  spend(
    datum: Option<CollateralDatum>,
    redeemer: CollateralRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(own_output) = find_own_input(self.inputs, utxo)

    let d =
      when datum is {
        Some(d) -> d
        None ->
          when own_output.datum is {
            InlineDatum(raw) -> {
              expect typed: CollateralDatum = raw
              typed
            }
            _ -> fail @"No valid datum found"
          }
      }

    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.borrower)
      Liquidate -> {
        let borrower_signed = list.has(self.extra_signatories, d.borrower)
        let in_default = is_in_default(d.liquidation_ratio)
        borrower_signed || in_default
      }
    }
  }
}

