pub type SplitDatum {
  party_a: ByteArray,
  party_b: ByteArray,
  share_a_bps: Int,
}

fn get_pkh_payment(address: Address) -> Option<ByteArray> {
  when address.payment_credential is {
    VerificationKey(pkh) -> Some(pkh)
    _ -> None
  }
}

fn sum_lovelace_to_pkh(outputs: List<Output>, pkh: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(output, acc) {
      when get_pkh_payment(output.address) is {
        Some(k) ->
          if k == pkh {
            acc + assets.lovelace_of(output.value)
          } else {
            acc
          }
        None -> acc
      }
    },
  )
}

fn get_input_lovelace(inputs: List<Input>, own_ref: OutputReference) -> Int {
  when list.find(inputs, fn(i) { i.output_reference == own_ref }) is {
    Some(input) -> assets.lovelace_of(input.output.value)
    None -> 0
  }
}

validator reward_split {
  spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let total_lovelace = get_input_lovelace(self.inputs, utxo)

    let expected_a = total_lovelace * d.share_a_bps / 10000
    let expected_b = total_lovelace - expected_a

    let actual_a = sum_lovelace_to_pkh(self.outputs, d.party_a)
    let actual_b = sum_lovelace_to_pkh(self.outputs, d.party_b)

    let valid_shares = actual_a >= expected_a && actual_b >= expected_b

    let valid_bps = d.share_a_bps >= 0 && d.share_a_bps <= 10000

    valid_bps && valid_shares
  }

  else(_) {
    fail
  }
}

