  fee_address: Option<ByteArray>,
  amount: Int,
}

fn address_has_pkh(addr: Address, pkh: ByteArray) -> Bool {
  when addr.payment_credential is {
    VerificationKey(k) -> k == pkh
    _ -> False
  }
}

fn find_output_to_pkh(outputs: List<Output>, pkh: ByteArray) -> Option<Output> {
  list.find(outputs, fn(o) { address_has_pkh(o.address, pkh) })
}

fn recipient_receives_amount(outputs: List<Output>, recipient: ByteArray, amount: Int) -> Bool {
  when find_output_to_pkh(outputs, recipient) is {
    Some(o) -> assets.lovelace_of(o.value) >= amount
    None -> False
  }
}

fn fee_check(outputs: List<Output>, fee_address: Option<ByteArray>) -> Bool {
  when fee_address is {
    Some(fee_pkh) ->
      when find_output_to_pkh(outputs, fee_pkh) is {
        Some(o) -> assets.lovelace_of(o.value) > 0
        None -> False
      }
    None -> True
  }
}

validator optional_fee {
  spend(
    datum: Option<TxDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let recipient_ok =
      recipient_receives_amount(self.outputs, d.recipient, d.amount)
    let fee_ok = fee_check(self.outputs, d.fee_address)
    recipient_ok && fee_ok
  }
}

