  token_policy: ByteArray,
  token_name: ByteArray,
  price: Int,
}

fn seller_gets_price(outputs: List<Output>, seller: ByteArray, price: Int) -> Bool {
  let seller_addr_payments =
    list.filter(
      outputs,
      fn(o) {
        when o.address.payment_credential is {
          address.VerificationKey(pkh) -> pkh == seller
          _ -> False
        }
      },
    )
  list.any(
    seller_addr_payments,
    fn(o) { assets.lovelace_of(o.value) >= price },
  )
}

fn buyer_gets_token(
  outputs: List<Output>,
  token_policy: ByteArray,
  token_name: ByteArray,
  script_address: Address,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address != script_address && assets.quantity_of(
        o.value,
        token_policy,
        token_name,
      ) >= 1
    },
  )
}

validator token_sale {
  spend(
    datum: Option<SaleDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let own_input =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })
    expect Some(inp) = own_input

    let script_address = inp.output.address

    let seller_paid = seller_gets_price(self.outputs, d.seller, d.price)

    let token_delivered =
      buyer_gets_token(self.outputs, d.token_policy, d.token_name, script_address)

    seller_paid && token_delivered
  }

  else(_) {
    fail
  }
}

