pub type BatchDatum {
  recipients: List<ByteArray>,
  amounts: List<Int>,
  sender: ByteArray,
}

fn zip_with_index(
  recipients: List<ByteArray>,
  amounts: List<Int>,
) -> List<(ByteArray, Int)> {
  when recipients is {
    [] -> []
    [r, ..rest_r] ->
      when amounts is {
        [] -> []
        [a, ..rest_a] -> [(r, a), ..zip_with_index(rest_r, rest_a)]
      }
  }
}

fn output_matches_recipient(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        VerificationKey(pkh) ->
          pkh == recipient && assets.lovelace_of(o.value) >= amount
        _ -> False
      }
    },
  )
}

fn all_recipients_paid(
  pairs: List<(ByteArray, Int)>,
  outputs: List<Output>,
) -> Bool {
  list.all(
    pairs,
    fn(pair) {
      let (recipient, amount) = pair
      output_matches_recipient(outputs, recipient, amount)
    },
  )
}

validator batch_transfer {
  spend(
    datum: Option<BatchDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let sender_signed = list.has(self.extra_signatories, d.sender)

    let pairs = zip_with_index(d.recipients, d.amounts)

    let has_recipients = !list.is_empty(pairs)

    let all_paid = all_recipients_paid(pairs, self.outputs)

    sender_signed && has_recipients && all_paid
  }
}

use aiken/collection/list
