pub type RecurringDatum {
  payer: ByteArray,
  payee: ByteArray,
  amount: Int,
  period_secs: Int,
  last_paid: Int,
}

pub type RecurringRedeemer {
  Pay
  Cancel
}

fn find_output_by_address(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator recurring_payment {
  spend(
    datum: Option<RecurringDatum>,
    redeemer: RecurringRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Pay -> {
        let deadline = d.last_paid + d.period_secs

        let period_elapsed =
          interval.is_entirely_after(self.validity_range, deadline)

        let payee_paid =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                address.VerificationKey(pkh) ->
                  pkh == d.payee && assets.lovelace_of(o.value) >= d.amount
                _ -> False
              }
            },
          )

        let own_input =
          list.find(
            self.inputs,
            fn(i) { i.output_reference == utxo },
          )

        expect Some(inp) = own_input
        let own_address = inp.output.address

        let continuing_output = find_output_by_address(self.outputs, own_address)

        let continuing_valid =
          when continuing_output is {
            Some(cont_out) -> {
              expect InlineDatum(raw) = cont_out.datum
              expect cont: RecurringDatum = raw
              cont.payer == d.payer && cont.payee == d.payee && cont.amount == d.amount && cont.period_secs == d.period_secs && cont.last_paid == deadline
            }
            None -> False
          }

        period_elapsed && payee_paid && continuing_valid
      }

      Cancel ->
        list.has(self.extra_signatories, d.payer)
    }
  }

  else(_) {
    False
  }
}

