  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type OracleDatum {
  price: Int,
  timestamp: Int,
  source: ByteArray,
}

pub type ConsumerDatum {
  min_price: Int,
  oracle_policy: ByteArray,
  oracle_asset_name: ByteArray,
  owner: ByteArray,
}

pub type ConsumerRedeemer {
  oracle_input_index: Int,
}

fn find_oracle_datum(
  reference_inputs: List<Input>,
  oracle_policy: ByteArray,
  oracle_asset_name: ByteArray,
) -> Option<OracleDatum> {
  let oracle_input =
    list.find(
      reference_inputs,
      fn(input) {
        assets.quantity_of(
          input.output.value,
          oracle_policy,
          oracle_asset_name,
        ) > 0
      },
    )
  when oracle_input is {
    Some(inp) ->
      when inp.output.datum is {
        InlineDatum(raw) -> {
          expect typed: OracleDatum = raw
          Some(typed)
        }
        _ -> None
      }
    None -> None
  }
}

validator oracle_consumer {
  spend(
    datum: Option<ConsumerDatum>,
    redeemer: ConsumerRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let maybe_oracle =
      find_oracle_datum(
        self.reference_inputs,
        d.oracle_policy,
        d.oracle_asset_name,
      )

    when maybe_oracle is {
      Some(oracle) -> {
        let price_valid = oracle.price >= d.min_price
        let signer_valid = list.has(self.extra_signatories, d.owner)
        price_valid && signer_valid
      }
      None -> False
    }
  }

  else(_) {
    fail
  }
}

