pub type AuctionDatum {
  highest_bid: Int,
  bidder: ByteArray,
  deadline: Int,
}

fn get_own_address(inputs: List<Input>, utxo: OutputReference) -> Address {
  expect Some(own_input) =
    list.find(inputs, fn(i) { i.output_reference == utxo })
  own_input.output.address
}

fn get_continuing_output(outputs: List<Output>, own_address: Address) -> Output {
  expect Some(cont_out) =
    list.find(outputs, fn(o) { o.address == own_address })
  cont_out
}

validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current) = datum

    let own_address = get_own_address(self.inputs, utxo)

    let cont_out = get_continuing_output(self.outputs, own_address)

    expect InlineDatum(raw) = cont_out.datum
    expect next: AuctionDatum = raw

    let before_deadline =
      interval.is_entirely_before(self.validity_range, current.deadline)

    let bid_increased = next.highest_bid > current.highest_bid

    let deadline_preserved = next.deadline == current.deadline

    let value_covers_bid =
      assets.lovelace_of(cont_out.value) >= next.highest_bid

    let bidder_signed = list.has(self.extra_signatories, next.bidder)

    before_deadline && bid_increased && deadline_preserved && value_covers_bid && bidder_signed
  }
}

