pub type SplitDatum {
  party_a: ByteArray,
  party_b: ByteArray,
  share_a_bps: Int,
}

fn get_payment_key(output: Output) -> Option<ByteArray> {
  when output.address.payment_credential is {
    VerificationKey(pkh) -> Some(pkh)
    _ -> None
  }
}

fn total_lovelace_to_key(outputs: List<Output>, pkh: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      when get_payment_key(o) is {
        Some(k) ->
          if k == pkh {
            acc + assets.lovelace_of(o.value)
          } else {
            acc
          }
        None -> acc
      }
    },
  )
}

validator reward_split {
  spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let total_a = total_lovelace_to_key(self.outputs, d.party_a)
    let total_b = total_lovelace_to_key(self.outputs, d.party_b)
    let total = total_a + total_b

    let expected_a = total * d.share_a_bps / 10000
    let expected_b = total * (10000 - d.share_a_bps) / 10000

    total_a >= expected_a && total_b >= expected_b && d.share_a_bps >= 0 && d.share_a_bps <= 10000
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/address.{Address}
