  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type SubDatum {
  subscriber: ByteArray,
  expiry: Int,
  fee_per_period: Int,
}

pub type SubRedeemer {
  Renew { new_expiry: Int }
  Cancel
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_address: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator subscription {
  spend(
    datum: Option<SubDatum>,
    redeemer: SubRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Renew { new_expiry } -> {
        // Subscriber must sign
        let signed = list.has(self.extra_signatories, d.subscriber)

        // Find own input to get own address
        expect Some(own_input) = find_own_input(self.inputs, utxo)
        let own_address = own_input.output.address

        // Find continuing output at own address
        expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

        // Continuing output must have updated datum
        let valid_datum = when cont_out.datum is {
          InlineDatum(raw) -> {
            expect cont: SubDatum = raw
            // Same subscriber and fee_per_period, new expiry must be greater
            cont.subscriber == d.subscriber && cont.fee_per_period == d.fee_per_period && cont.expiry == new_expiry && new_expiry > d.expiry
          }
          _ -> False
        }

        // The continuing output must contain at least the original lovelace
        // plus the fee for the renewal period
        let own_input_lovelace = assets.lovelace_of(own_input.output.value)
        let cont_lovelace = assets.lovelace_of(cont_out.value)
        let fee_paid = cont_lovelace >= own_input_lovelace + d.fee_per_period

        signed && valid_datum && fee_paid
      }

      Cancel -> {
        // Allow cancel only after expiry
        let after_expiry = interval.is_entirely_after(self.validity_range, d.expiry)

        // Only subscriber can cancel (or anyone after expiry — here we restrict to subscriber)
        let signed = list.has(self.extra_signatories, d.subscriber)

        after_expiry && signed
      }
    }
  }

  else(_) {
    False
  }
}

