use cardano/transaction.{InlineDatum, DatumHash, NoDatum, Output, OutputReference, Transaction}
use cardano/address.{Address}
use aiken/collection/list

pub type EscrowDatum {
  seller: ByteArray,
  buyer: ByteArray,
  amount: Int,
  deadline: Int,
}

pub type EscrowRedeemer {
  Complete
  Refund
  Dispute
}

fn find_output_to(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator safe_escrow {
  spend(
    datum: Option<EscrowDatum>,
    redeemer: EscrowRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    // Find own input to get full output with datum
    let own_input =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    expect Some(input) = own_input

    // Pattern match on the datum field of the output
    when input.output.datum is {
      InlineDatum(raw) -> {
        expect typed: EscrowDatum = raw

        when redeemer is {
          Complete -> {
            // Seller must sign to complete the escrow
            list.has(self.extra_signatories, typed.buyer) && list.has(
              self.extra_signatories,
              typed.seller,
            )
          }

          Refund -> {
            // Only seller can refund before deadline
            list.has(self.extra_signatories, typed.seller)
          }

          Dispute -> {
            // Either party can raise a dispute
            list.has(self.extra_signatories, typed.buyer) || list.has(
              self.extra_signatories,
              typed.seller,
            )
          }
        }
      }

      DatumHash(_) -> fail @"DatumHash not supported: must use InlineDatum"

      NoDatum -> fail @"NoDatum not supported: must use InlineDatum"
    }
  }
}

