pub type VersionedDatum {
  version: Int,
  admin: ByteArray,
  params: Int,
}

pub type Action {
  Upgrade { new_version: Int, new_params: Int }
  Use
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_input: Input) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_input.output.address })
}

validator upgradeable {
  spend(
    datum: Option<VersionedDatum>,
    redeemer: Action,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Upgrade { new_version, new_params } -> {
        expect True = list.has(self.extra_signatories, d.admin)
        expect True = new_version > d.version

        expect Some(own_in) = find_own_input(self.inputs, utxo)
        expect Some(cont_out) = find_continuing_output(self.outputs, own_in)

        when cont_out.datum is {
          InlineDatum(raw) -> {
            expect next: VersionedDatum = raw
            next.version == new_version && next.admin == d.admin && next.params == new_params
          }
          _ -> False
        }
      }

      Use -> True
    }
  }
}

