fn address_from_pkh(pkh: ByteArray) -> Address {
  Address {
    payment_credential: address.VerificationKey(pkh),
    stake_credential: None,
  }
}

fn seller_receives_price(outputs: List<Output>, seller_addr: Address, price: Int) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == seller_addr && assets.lovelace_of(o.value) >= price
    },
  )
}

fn buyer_receives_token(
  outputs: List<Output>,
  signatories: List<ByteArray>,
  token_policy: ByteArray,
  token_name: ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        address.VerificationKey(pkh) ->
          list.has(signatories, pkh) && assets.quantity_of(
            o.value,
            token_policy,
            token_name,
          ) >= 1
        address.Script(_) -> False
      }
    },
  )
}

validator token_sale {
  spend(
    datum: Option<SaleDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let seller_addr = address_from_pkh(d.seller)

    let seller_paid = seller_receives_price(self.outputs, seller_addr, d.price)

    let buyer_gets_token =
      buyer_receives_token(
        self.outputs,
        self.extra_signatories,
        d.token_policy,
        d.token_name,
      )

    seller_paid && buyer_gets_token
  }

  else(_) {
    fail
  }
}

