pub type FundDatum {
  goal: Int,
  deadline: Int,
  creator: ByteArray,
}

pub type FundRedeemer {
  Withdraw
  Refund
}

validator crowdfund {
  spend(
    datum: Option<FundDatum>,
    redeemer: FundRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Withdraw -> {
        let after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)

        let signed_by_creator =
          list.has(self.extra_signatories, d.creator)

        let total_funds =
          list.foldl(
            self.inputs,
            0,
            fn(input, acc) {
              acc + assets.lovelace_of(input.output.value)
            },
          )

        let goal_met = total_funds >= d.goal

        after_deadline && signed_by_creator && goal_met
      }

      Refund -> {
        let after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)

        let total_funds =
          list.foldl(
            self.inputs,
            0,
            fn(input, acc) {
              acc + assets.lovelace_of(input.output.value)
            },
          )

        let goal_not_met = total_funds < d.goal

        after_deadline && goal_not_met
      }
    }
  }

  else(_) {
    fail
  }
}

