  quantity: Int,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn get_payment_output(outputs: List<Output>, seller_address: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == seller_address })
}

validator whitelist_sale {
  spend(
    datum: Option<WhitelistDatum>,
    redeemer: WhitelistRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let buyer = redeemer.buyer
    let quantity = redeemer.quantity

    let buyer_in_whitelist = list.has(d.whitelist, buyer)

    let quantity_valid = quantity >= 1 && quantity <= d.max_per_wallet

    let buyer_signed = list.has(self.extra_signatories, buyer)

    let total_cost = d.price * quantity

    expect Some(own_input) = find_own_input(self.inputs, utxo)
    let script_address = own_input.output.address

    let payment_received =
      list.any(
        self.outputs,
        fn(o) {
          o.address == script_address && assets.lovelace_of(o.value) >= total_cost
        },
      )

    let continuing_output =
      list.find(self.outputs, fn(o) { o.address == script_address })

    let datum_preserved =
      when continuing_output is {
        Some(cont_out) ->
          when cont_out.datum is {
            InlineDatum(raw) -> {
              expect cont: WhitelistDatum = raw
              cont.whitelist == d.whitelist && cont.price == d.price && cont.max_per_wallet == d.max_per_wallet
            }
            _ -> False
          }
        None -> True
      }

    buyer_in_whitelist && quantity_valid && buyer_signed && payment_received && datum_preserved
  }

  else(_) {
    fail
  }
}

