        expect True = next_threshold > d.threshold

        expect Some(own_in) = find_own_input(self.inputs, utxo)
        expect Some(cont_out) = find_continuing_output(self.outputs, own_in)

        when cont_out.datum is {
          InlineDatum(raw) -> {
            expect next: ConfigDatum = raw
            next.revision == next_revision && next.curator == d.curator && next.threshold == next_threshold
          }
          _ -> False
        }
      }

      Apply -> True
    }
  }
}

