pub type SubscriptionDatum {
  subscriber: ByteArray,
  recipient: ByteArray,
  payment_lovelace: Int,
  interval_secs: Int,
  next_due: Int,
}

pub type SubscriptionRedeemer {
  Pay
  Cancel
}

fn find_output_at_address(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator scheduled_transfer {
  spend(
    datum: Option<SubscriptionDatum>,
    redeemer: SubscriptionRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Pay -> {
        let time_reached =
          interval.is_entirely_after(self.validity_range, d.next_due)

        let recipient_paid =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                VerificationKey(pkh) ->
                  pkh == d.recipient && assets.lovelace_of(o.value) >= d.payment_lovelace
                _ -> False
              }
            },
          )

        let own_input =
          list.find(
            self.inputs,
            fn(i) { i.output_reference == utxo },
          )

        expect Some(inp) = own_input
        let own_address = inp.output.address

        let continuing_output = find_output_at_address(self.outputs, own_address)

        let continuing_valid =
          when continuing_output is {
            Some(cont_out) -> {
              expect InlineDatum(raw) = cont_out.datum
              expect cont: SubscriptionDatum = raw
              cont.subscriber == d.subscriber && cont.recipient == d.recipient && cont.payment_lovelace == d.payment_lovelace && cont.interval_secs == d.interval_secs && cont.next_due == d.next_due + d.interval_secs
            }
            None -> False
          }

        time_reached && recipient_paid && continuing_valid
      }

      Cancel ->
        list.has(self.extra_signatories, d.subscriber)
    }
  }

  else(_) {
    False
  }
}

