  expiry: Int,
  beneficiary: ByteArray,
  min_contribution: Int,
}

pub type CampaignAction {
  Claim
  Reclaim
}

validator campaign_vault {
  spend(
    datum: Option<CampaignDatum>,
    redeemer: CampaignAction,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Claim -> {
        let past_expiry =
          interval.is_entirely_after(self.validity_range, d.expiry)

        let signed_by_beneficiary =
          list.has(self.extra_signatories, d.beneficiary)

        let total_lovelace =
          list.foldl(
            self.inputs,
            0,
            fn(input, acc) {
              acc + assets.lovelace_of(input.output.value)
            },
          )

        let target_reached = total_lovelace >= d.target_lovelace

        past_expiry && signed_by_beneficiary && target_reached
      }

      Reclaim -> {
        let past_expiry =
          interval.is_entirely_after(self.validity_range, d.expiry)

        let total_lovelace =
          list.foldl(
            self.inputs,
            0,
            fn(input, acc) {
              acc + assets.lovelace_of(input.output.value)
            },
          )

        let target_not_reached = total_lovelace < d.target_lovelace

        past_expiry && target_not_reached
      }
    }
  }

  else(_) {
    fail
  }
}

