pub type PayoutDatum {
  payees: List<ByteArray>,
  minimums: List<Int>,
  authorizer: ByteArray,
  expiry: Int,
}

fn zip_payees_minimums(
  payees: List<ByteArray>,
  minimums: List<Int>,
) -> List<(ByteArray, Int)> {
  when payees is {
    [] -> []
    [p, ..rest_p] ->
      when minimums is {
        [] -> []
        [m, ..rest_m] -> [(p, m), ..zip_payees_minimums(rest_p, rest_m)]
      }
  }
}

fn output_exceeds_minimum(
  outputs: List<Output>,
  payee: ByteArray,
  minimum: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        VerificationKey(pkh) ->
          pkh == payee && assets.lovelace_of(o.value) > minimum
        _ -> False
      }
    },
  )
}

fn all_payees_covered(
  pairs: List<(ByteArray, Int)>,
  outputs: List<Output>,
) -> Bool {
  list.all(
    pairs,
    fn(pair) {
      let (payee, minimum) = pair
      output_exceeds_minimum(outputs, payee, minimum)
    },
  )
}

validator multi_payout {
  spend(
    datum: Option<PayoutDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let authorizer_signed = list.has(self.extra_signatories, d.authorizer)

    let before_expiry = interval.is_entirely_before(self.validity_range, d.expiry)

    let pairs = zip_payees_minimums(d.payees, d.minimums)

    let has_pairs = !list.is_empty(pairs)

    let all_covered = all_payees_covered(pairs, self.outputs)

    authorizer_signed && before_expiry && has_pairs && all_covered
  }
}

