use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type SwapPoolState {
  token_x_reserve: Int,
  token_y_reserve: Int,
  total_shares: Int,
}

pub type ExitRedeemer {
  shares_to_burn: Int,
  minimum_x_out: Int,
  minimum_y_out: Int,
}

fn find_continuing_pool(outputs: List<Output>, nft_policy: ByteArray) -> Option<Output> {
  list.find(
    outputs,
    fn(o) { assets.quantity_of(o.value, nft_policy, "pool_nft") > 0 },
  )
}

validator amm_liquidity_exit(
  pool_nft_policy: ByteArray,
  share_token_policy: ByteArray,
  share_token_name: ByteArray,
) {
  spend(
    datum: Option<SwapPoolState>,
    redeemer: ExitRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let shares_to_burn = redeemer.shares_to_burn
    let minimum_x_out = redeemer.minimum_x_out
    let minimum_y_out = redeemer.minimum_y_out

    // shares_to_burn must be positive
    let burn_positive = shares_to_burn > 0

    // Prevent full pool drain: must burn strictly less than total_shares
    let no_full_drain = shares_to_burn < d.total_shares

    // total_shares must be positive
    let shares_valid = d.total_shares > 0

    // Calculate proportional withdrawal amounts
    let withdrawn_x = d.token_x_reserve * shares_to_burn / d.total_shares
    let withdrawn_y = d.token_y_reserve * shares_to_burn / d.total_shares

    // Ensure withdrawn amounts meet minimum thresholds
    let slippage_ok = withdrawn_x >= minimum_x_out && withdrawn_y >= minimum_y_out

    // Check that share tokens are burned in mint field (negative quantity)
    let burned_shares = assets.quantity_of(self.mint, share_token_policy, share_token_name)
    let burn_matches = burned_shares == -shares_to_burn

    // Verify continuing pool output has correctly updated state
    let pool_state_valid =
      when find_continuing_pool(self.outputs, pool_nft_policy) is {
        Some(pool_out) ->
          when pool_out.datum is {
            InlineDatum(raw) -> {
              expect new_state: SwapPoolState = raw
              let expected_x = d.token_x_reserve - withdrawn_x
              let expected_y = d.token_y_reserve - withdrawn_y
              let expected_shares = d.total_shares - shares_to_burn
              new_state.token_x_reserve == expected_x && new_state.token_y_reserve == expected_y && new_state.total_shares == expected_shares && new_state.token_x_reserve > 0 && new_state.token_y_reserve > 0 && new_state.total_shares > 0
            }
            _ -> False
          }
        None -> False
      }

    burn_positive && no_full_drain && shares_valid && slippage_ok && burn_matches && pool_state_valid
  }

  else(_) {
    fail
  }
}

