fn total_lovelace(outputs: List<Output>) -> Int {
  list.foldl(outputs, 0, fn(output, acc) { acc + assets.lovelace_of(output.value) })
}

fn all_outputs_meet_royalty(outputs: List<Output>, min_royalty: Int) -> Bool {
  list.all(outputs, fn(output) { assets.lovelace_of(output.value) >= min_royalty })
}

validator token_marketplace {
  spend(
    datum: Option<MarketDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let outs = vendor_outputs(self.outputs, d.vendor)
    let total = total_lovelace(outs)
    let royalty_ok = all_outputs_meet_royalty(outs, d.min_royalty)
    total >= d.ask_lovelace && royalty_ok
  }
}

