fn lender_has_signed(tx: Transaction, lender: ByteArray) -> Bool {
  list.any(tx.extra_signatories, fn(sig) { sig == lender })
}

fn position_referenced_in_output(
  outputs: List<Output>,
  position_id: ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      when output.datum is {
        InlineDatum(raw) -> {
          expect d: LoanCollateral = raw
          d.position_id == position_id
        }
        _ -> False
      }
    },
  )
}

validator secured_loan_vault {
  spend(
    datum: Option<LoanCollateral>,
    redeemer: VaultRedeemer,
    _output_reference: Data,
    tx: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Withdraw -> lender_has_signed(tx, d.lender)
      ForceClosure { is_underwater } -> {
        let signed = lender_has_signed(tx, d.lender)
        let unhealthy = d.health_factor < 150
        let position_present =
          position_referenced_in_output(tx.outputs, d.position_id)
        unhealthy && position_present && (signed || is_underwater)
      }
    }
  }

  else(_) {
    fail
  }
}

