pub type BidState {
  top_price: Int,
  winner: ByteArray,
  end_time: Int,
  min_increment: Int,
}

pub type BidRedeemer {
  offer_price: Int,
  offer_bidder: ByteArray,
}

validator nft_auction_escrow {
  spend(
    datum: Option<BidState>,
    redeemer: BidRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current_state) = datum

    let auction_still_open =
      interval.is_entirely_before(self.validity_range, current_state.end_time)

    let bid_meets_increment =
      redeemer.offer_price >= current_state.top_price + current_state.min_increment

    let own_input =
      list.find(self.inputs, fn(input) { input.output_reference == utxo })

    expect Some(my_input) = own_input

    let own_address = my_input.output.address

    let continuing_output_valid =
      list.any(
        self.outputs,
        fn(output) {
          when output.datum is {
            InlineDatum(raw) -> {
              expect new_state: BidState = raw
              let price_matches = new_state.top_price == redeemer.offer_price
              let winner_matches = new_state.winner == redeemer.offer_bidder
              let end_time_preserved =
                new_state.end_time == current_state.end_time
              let increment_preserved =
                new_state.min_increment == current_state.min_increment
              let address_matches = output.address == own_address
              let value_covers_bid =
                assets.lovelace_of(output.value) >= redeemer.offer_price
              price_matches && winner_matches && end_time_preserved && increment_preserved && address_matches && value_covers_bid
            }
            _ -> False
          }
        },
      )

    auction_still_open && bid_meets_increment && continuing_output_valid
  }

  else(_) {
    fail
  }
}

