pub type DistributionDatum {
  recipient_x: ByteArray,
  recipient_y: ByteArray,
  recipient_z: ByteArray,
  portion_x_bps: Int,
  portion_y_bps: Int,
}

fn extract_payment_key(output: Output) -> Option<ByteArray> {
  when output.address.payment_credential is {
    VerificationKey(pkh) -> Some(pkh)
    _ -> None
  }
}

fn sum_lovelace_to_key(outputs: List<Output>, pkh: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      when extract_payment_key(o) is {
        Some(k) ->
          if k == pkh {
            acc + assets.lovelace_of(o.value)
          } else {
            acc
          }
        None -> acc
      }
    },
  )
}

validator fee_distribution {
  spend(
    datum: Option<DistributionDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let portion_z_bps = 10000 - d.portion_x_bps - d.portion_y_bps

    let portions_valid =
      d.portion_x_bps >= 0 && d.portion_y_bps >= 0 && portion_z_bps >= 0 && d.portion_x_bps + d.portion_y_bps <= 10000

    let total_x = sum_lovelace_to_key(self.outputs, d.recipient_x)
    let total_y = sum_lovelace_to_key(self.outputs, d.recipient_y)
    let total_z = sum_lovelace_to_key(self.outputs, d.recipient_z)
    let total = total_x + total_y + total_z

    let expected_x = total * d.portion_x_bps / 10000
    let expected_y = total * d.portion_y_bps / 10000
    let expected_z = total * portion_z_bps / 10000

    portions_valid && total_x >= expected_x && total_y >= expected_y && total_z >= expected_z
  }
}

