}

validator bounded_treasury {
  spend(datum: Option<TreasuryDatum>, _redeemer: Data, _utxo: OutputReference, self: Transaction) {
    expect Some(d) = datum

    let custodian_signed = list.has(self.extra_signatories, d.custodian)

    let total_out = sum_output_lovelace(self.outputs)

    let in_range =
      total_out >= d.allowed_range.lower && total_out <= d.allowed_range.upper

    let signer_count = list.length(self.extra_signatories)

    let enough_signers = signer_count >= d.required_signers

    custodian_signed && in_range && enough_signers
  }
}

