pub type PresaleDatum {
  approved_buyers: List<ByteArray>,
  token_price: Int,
  purchase_cap: Int,
  min_purchase: Int,
}

pub type PresaleRedeemer {
  purchaser: ByteArray,
  amount: Int,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

validator presale_gated {
  spend(
    datum: Option<PresaleDatum>,
    redeemer: PresaleRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let purchaser = redeemer.purchaser
    let amount = redeemer.amount

    let buyer_approved = list.has(d.approved_buyers, purchaser)

    let amount_valid = amount >= d.min_purchase && amount <= d.purchase_cap

    let buyer_signed = list.has(self.extra_signatories, purchaser)

    let total_cost = d.token_price * amount

    expect Some(own_input) = find_own_input(self.inputs, utxo)
    let script_address = own_input.output.address

    let payment_received =
      list.any(
        self.outputs,
        fn(o) {
          o.address == script_address && assets.lovelace_of(o.value) >= total_cost
        },
      )

    let continuing_output =
      list.find(self.outputs, fn(o) { o.address == script_address })

    let datum_preserved =
      when continuing_output is {
        Some(cont_out) ->
          when cont_out.datum is {
            InlineDatum(raw) -> {
              expect cont: PresaleDatum = raw
              cont.approved_buyers == d.approved_buyers && cont.token_price == d.token_price && cont.purchase_cap == d.purchase_cap && cont.min_purchase == d.min_purchase
            }
            _ -> False
          }
        None -> True
      }

    buyer_approved && amount_valid && buyer_signed && payment_received && datum_preserved
  }

  else(_) {
    fail
  }
}

