use aiken/collection/list
use cardano/address.{Address}
use cardano/transaction.{
  DatumHash, InlineDatum, NoDatum, Output, OutputReference, Transaction,
}

pub type PaymentDatum {
  payer: ByteArray,
  payee: ByteArray,
  lovelace: Int,
  expiry: Int,
}

pub type PaymentRedeemer {
  Release
  Cancel
  Claim
}

fn find_output_to(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator locked_payment {
  spend(
    datum: Option<PaymentDatum>,
    redeemer: PaymentRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    let own_input =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    expect Some(input) = own_input

    when input.output.datum is {
      InlineDatum(raw) -> {
        expect typed: PaymentDatum = raw

        when redeemer is {
          Release -> {
            // Both payer and payee must sign to release funds
            list.has(self.extra_signatories, typed.payer) && list.has(
              self.extra_signatories,
              typed.payee,
            )
          }

          Cancel -> {
            // Only the payer can cancel and reclaim funds
            list.has(self.extra_signatories, typed.payer)
          }

          Claim -> {
            // Only the payee can claim the locked funds
            list.has(self.extra_signatories, typed.payee)
          }
        }
      }

      DatumHash(_) -> fail @"DatumHash not supported: must use InlineDatum"

      NoDatum -> fail @"NoDatum not supported: must use InlineDatum"
    }
  }
}

