fn find_feed_datum(
  reference_inputs: List<Input>,
  feed_policy: ByteArray,
  feed_asset_name: ByteArray,
) -> Option<FeedDatum> {
  let feed_input =
    list.find(
      reference_inputs,
      fn(input) {
        assets.quantity_of(
          input.output.value,
          feed_policy,
          feed_asset_name,
        ) > 0
      },
    )
  when feed_input is {
    Some(inp) ->
      when inp.output.datum is {
        InlineDatum(raw) -> {
          expect typed: FeedDatum = raw
          Some(typed)
        }
        _ -> None
      }
    None -> None
  }
