validator price_feed_guard {
  spend(
    datum: Option<GuardDatum>,
    _redeemer: GuardRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let maybe_feed =
      find_feed_datum(
        self.reference_inputs,
        d.feed_policy,
        d.feed_asset_name,
      )

    when maybe_feed is {
      Some(feed) -> {
        let rate_valid = feed.rate <= d.max_rate
        let signer_valid = list.has(self.extra_signatories, d.operator)
        let time_valid = interval.is_entirely_before(self.validity_range, d.deadline)
        rate_valid && signer_valid && time_valid
      }
      None -> False
    }
  }

  else(_) {
    fail
  }
}

