  unit_price: Int,
  purchase_limit: Int,
  treasury: ByteArray,
}

pub type PurchaseRedeemer {
  purchaser: ByteArray,
  quantity: Int,
}

validator exclusive_drop {
  spend(
    datum: Option<SaleDatum>,
    redeemer: PurchaseRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let purchaser = redeemer.purchaser
