    let is_approved = list.has(d.approved_buyers, purchaser)

    let purchaser_signed = list.has(self.extra_signatories, purchaser)

    let quantity_valid = quantity >= 1 && quantity <= d.purchase_limit

    let total_due = d.unit_price * quantity

    let treasury_paid =
      list.any(
        self.outputs,
        fn(output: Output) {
          when output.address.payment_credential is {
            address.VerificationKey(pkh) ->
              pkh == d.treasury && assets.lovelace_of(output.value) >= total_due
            _ -> False
          }
        },
      )

    is_approved && purchaser_signed && quantity_valid && treasury_paid
  }

  else(_) {
    fail
  }
}

