pub type BidState {
  top_amount: Int,
  top_bidder: ByteArray,
  end_time: Int,
  min_increment: Int,
}

validator timed_auction {
  spend(
    datum: Option<BidState>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current) = datum

    let auction_still_open =
      interval.is_entirely_before(self.validity_range, current.end_time)

    expect Some(cont_out) =
      list.find(
        self.outputs,
        fn(o) {
          when o.datum is {
            InlineDatum(raw) -> {
              expect typed: BidState = raw
              typed.end_time == current.end_time && typed.min_increment == current.min_increment
            }
            _ -> False
          }
        },
      )

    expect InlineDatum(raw) = cont_out.datum
    expect new_state: BidState = raw

    let bid_high_enough =
      new_state.top_amount >= current.top_amount + current.min_increment

    let increment_unchanged =
      new_state.min_increment == current.min_increment

    let new_bidder_signed =
      list.has(self.extra_signatories, new_state.top_bidder)

    let output_covers_bid =
      assets.lovelace_of(cont_out.value) >= new_state.top_amount

    auction_still_open && bid_high_enough && increment_unchanged && new_bidder_signed && output_covers_bid
  }

  else(_) {
    False
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type CampaignDatum {
  target: Int,
  expiry: Int,
  beneficiary: ByteArray,
  min_contribution: Int,
}

pub type CampaignRedeemer {
  Collect
  Reclaim
}

validator community_raise {
  spend(
    datum: Option<CampaignDatum>,
    redeemer: CampaignRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Collect -> {
        let after_expiry =
          interval.is_entirely_after(self.validity_range, d.expiry)

        let signed_by_beneficiary =
          list.has(self.extra_signatories, d.beneficiary)

        let total_funds =
          list.foldl(
            self.inputs,
            0,
            fn(input, acc) {
              acc + assets.lovelace_of(input.output.value)
            },
          )

        let target_reached = total_funds >= d.target

        after_expiry && signed_by_beneficiary && target_reached
      }

      Reclaim -> {
        let after_expiry =
          interval.is_entirely_after(self.validity_range, d.expiry)

        let total_funds =
          list.foldl(
            self.inputs,
            0,
            fn(input, acc) {
              acc + assets.lovelace_of(input.output.value)
            },
          )

        let target_not_reached = total_funds < d.target

        let all_outputs_meet_minimum =
          list.all(
            self.outputs,
            fn(output) {
              assets.lovelace_of(output.value) >= d.min_contribution
            },
          )

        after_expiry && target_not_reached && all_outputs_meet_minimum
      }
    }
  }

  else(_) {
    fail
  }
}

