fn find_own_input(
  inputs: List<transaction.Input>,
  utxo: OutputReference,
) -> Option<Output> {
  when inputs is {
    [] -> None
    [input, ..rest] ->
      if input.output_reference == utxo {
        Some(input.output)
      } else {
        find_own_input(rest, utxo)
      }
  }
}

fn is_unhealthy(health_factor: Int) -> Bool {
  health_factor < 100
}

validator loan_position_vault {
  spend(
    datum: Option<LoanDatum>,
    redeemer: LoanRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(own_output) = find_own_input(self.inputs, utxo)

    let d =
      when datum is {
        Some(d) -> d
        None ->
          when own_output.datum is {
            InlineDatum(raw) -> {
              expect typed: LoanDatum = raw
              typed
            }
            _ -> fail @"No valid datum found"
          }
      }

    when redeemer is {
      Withdraw -> list.has(self.extra_signatories, d.lender)
      ForceClose -> {
        let lender_signed = list.has(self.extra_signatories, d.lender)
        let unhealthy = is_unhealthy(d.health_factor)
        lender_signed || unhealthy
      }
    }
  }
}

