fn sequence_not_processed(
  reference_inputs: List<Input>,
  sequence: ByteArray,
) -> Bool {
  let sequence_records =
    list.filter_map(reference_inputs, fn(inp) { find_sequence_datum(inp) })
  when sequence_records is {
    [] -> False
    _ ->
      list.all(
        sequence_records,
        fn(sd) { !list.has(sd.processed_sequences, sequence) },
      )
}
