    expect Some(transfer) = datum

    let sequence_valid =
      sequence_not_processed(tx.reference_inputs, transfer.sequence)

    let beneficiary_ok =
      beneficiary_signed(tx, transfer.beneficiary)

    let meets_minimum = transfer.value >= 1000

    sequence_valid && beneficiary_ok && meets_minimum
  }

  else(_) {
    False
  }
}

