pub type ListingDatum {
  vendor: ByteArray,
  asset_policy: ByteArray,
  asset_name: ByteArray,
  asking_price: Int,
  min_lovelace: Int,
}

fn vendor_receives_payment(
  outputs: List<Output>,
  vendor: ByteArray,
  asking_price: Int,
  min_lovelace: Int,
) -> Bool {
  let vendor_outputs =
    list.filter(
      outputs,
      fn(o) {
        when o.address.payment_credential is {
          VerificationKey(pkh) -> pkh == vendor
          _ -> False
        }
      },
    )
  list.any(
    vendor_outputs,
    fn(o) {
      let lovelace = assets.lovelace_of(o.value)
      lovelace >= asking_price && lovelace >= min_lovelace
    },
  )
}

fn buyer_receives_nft(
  outputs: List<Output>,
  asset_policy: ByteArray,
  asset_name: ByteArray,
  script_address: Address,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address != script_address && assets.quantity_of(
        o.value,
        asset_policy,
        asset_name,
      ) >= 1
    },
  )
}

fn vendor_is_vkey(vendor_pkh: ByteArray, outputs: List<Output>) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        VerificationKey(pkh) -> pkh == vendor_pkh
        _ -> False
      }
    },
  )
}

validator nft_marketplace {
  spend(
    datum: Option<ListingDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let own_input =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })
    expect Some(inp) = own_input

    let script_address = inp.output.address

    let payment_valid =
      vendor_receives_payment(
        self.outputs,
        d.vendor,
        d.asking_price,
        d.min_lovelace,
      )

    let nft_delivered =
      buyer_receives_nft(
        self.outputs,
        d.asset_policy,
        d.asset_name,
        script_address,
      )

    let vendor_is_key = vendor_is_vkey(d.vendor, self.outputs)

    payment_valid && nft_delivered && vendor_is_key
  }

  else(_) {
    fail
  }
}

