pub type PaymentSpec {
  beneficiary: ByteArray,
  treasury: Option<ByteArray>,
  min_lovelace: Int,
}

fn pkh_matches(addr: Address, pkh: ByteArray) -> Bool {
  when addr.payment_credential is {
    VerificationKey(k) -> k == pkh
    _ -> False
  }
}

fn find_output_for_pkh(outputs: List<Output>, pkh: ByteArray) -> Option<Output> {
  list.find(outputs, fn(o) { pkh_matches(o.address, pkh) })
}

fn beneficiary_receives_minimum(
  outputs: List<Output>,
  beneficiary: ByteArray,
  min_lovelace: Int,
) -> Bool {
  when find_output_for_pkh(outputs, beneficiary) is {
    Some(o) -> assets.lovelace_of(o.value) >= min_lovelace
    None -> False
  }
}

fn treasury_routing_check(
  outputs: List<Output>,
  treasury: Option<ByteArray>,
  min_lovelace: Int,
) -> Bool {
  when treasury is {
    Some(treasury_pkh) -> {
      let required = min_lovelace / 10
      when find_output_for_pkh(outputs, treasury_pkh) is {
        Some(o) -> assets.lovelace_of(o.value) >= required
        None -> False
      }
    }
    None -> True
  }
}

validator conditional_routing {
  spend(
    datum: Option<PaymentSpec>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let beneficiary_ok =
      beneficiary_receives_minimum(self.outputs, d.beneficiary, d.min_lovelace)
    let treasury_ok =
      treasury_routing_check(self.outputs, d.treasury, d.min_lovelace)
    beneficiary_ok && treasury_ok
  }
}

use cardano/transaction.{Transaction, Output, OutputReference, InlineDatum}
use aiken/collection/list

pub type SettingsDatum {
  operator: ByteArray,
  swap_fee_bps: Int,
  max_swap_bps: Int,
  frozen: Bool,
}

pub type SettingsRedeemer {
  UpdateSwapFee { new_swap_fee_bps: Int }
  UpdateMaxSwap { new_max_swap_bps: Int }
  Freeze
  Unfreeze
  CloseSettings
}

fn valid_bps(bps: Int) -> Bool {
  bps >= 0 && bps <= 10000
}

fn apply_redeemer(datum: SettingsDatum, redeemer: SettingsRedeemer) -> Bool {
  when redeemer is {
    UpdateSwapFee { new_swap_fee_bps } ->
      valid_bps(new_swap_fee_bps) && new_swap_fee_bps <= datum.max_swap_bps
    UpdateMaxSwap { new_max_swap_bps } ->
      valid_bps(new_max_swap_bps) && new_max_swap_bps >= datum.swap_fee_bps
    Freeze ->
      !datum.frozen
    Unfreeze ->
      datum.frozen
    CloseSettings ->
      True
  }
}

fn find_continuing_output(outputs: List<Output>, datum: SettingsDatum, redeemer: SettingsRedeemer) -> Bool {
  when redeemer is {
    CloseSettings -> True
    UpdateSwapFee { new_swap_fee_bps } ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: SettingsDatum = raw
            new_datum.operator == datum.operator &&
            new_datum.swap_fee_bps == new_swap_fee_bps &&
            new_datum.max_swap_bps == datum.max_swap_bps &&
            new_datum.frozen == datum.frozen
          }
          _ -> False
        }
      })
    UpdateMaxSwap { new_max_swap_bps } ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: SettingsDatum = raw
            new_datum.operator == datum.operator &&
            new_datum.swap_fee_bps == datum.swap_fee_bps &&
            new_datum.max_swap_bps == new_max_swap_bps &&
            new_datum.frozen == datum.frozen
          }
          _ -> False
        }
      })
    Freeze ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: SettingsDatum = raw
            new_datum.operator == datum.operator &&
            new_datum.swap_fee_bps == datum.swap_fee_bps &&
            new_datum.max_swap_bps == datum.max_swap_bps &&
            new_datum.frozen == True
          }
          _ -> False
        }
      })
    Unfreeze ->
      list.any(outputs, fn(o) {
        when o.datum is {
          InlineDatum(raw) -> {
            expect new_datum: SettingsDatum = raw
            new_datum.operator == datum.operator &&
            new_datum.swap_fee_bps == datum.swap_fee_bps &&
            new_datum.max_swap_bps == datum.max_swap_bps &&
            new_datum.frozen == False
          }
          _ -> False
        }
      })
  }
}

validator exchange_settings {
  spend(datum: Option<SettingsDatum>, redeemer: SettingsRedeemer, _utxo: OutputReference, self: Transaction) {
    expect Some(d) = datum

    let operator_signed = list.has(self.extra_signatories, d.operator)

    let not_frozen_or_exempt =
      when redeemer is {
        Unfreeze -> True
        CloseSettings -> True
        _ -> !d.frozen
      }

    let redeemer_valid = apply_redeemer(d, redeemer)

    let output_valid = find_continuing_output(self.outputs, d, redeemer)

    operator_signed && not_frozen_or_exempt && redeemer_valid && output_valid
  }

  else(_) {
    False
  }
}

