fn claimable_tokens(datum: UnlockDatum, current_time: Int) -> Int {
  if current_time <= datum.cliff_time {
    0
  } else if current_time >= datum.maturity_time {
    datum.total_tokens
  } else {
    let elapsed = current_time - datum.cliff_time
    let total_duration = datum.maturity_time - datum.cliff_time
    datum.total_tokens * elapsed / total_duration
  }
}

