pub type SubscriptionDatum {
  subscriber: ByteArray,
  provider: ByteArray,
  fee: Int,
  interval_secs: Int,
  next_due: Int,
}

pub type SubscriptionRedeemer {
  Renew
  Cancel
}

fn find_output_at(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator subscription_service {
  spend(
    datum: Option<SubscriptionDatum>,
    redeemer: SubscriptionRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Renew -> {
        let due_deadline = d.next_due

        let interval_elapsed =
          interval.is_entirely_after(self.validity_range, due_deadline)

        let provider_paid =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                VerificationKey(pkh) ->
                  pkh == d.provider && assets.lovelace_of(o.value) >= d.fee
                _ -> False
              }
            },
          )

        let own_input =
          list.find(
            self.inputs,
            fn(i) { i.output_reference == utxo },
          )

        expect Some(inp) = own_input
        let own_address = inp.output.address

        let continuing_output = find_output_at(self.outputs, own_address)

        let continuing_valid =
          when continuing_output is {
            Some(cont_out) -> {
              expect InlineDatum(raw) = cont_out.datum
              expect cont: SubscriptionDatum = raw
              cont.subscriber == d.subscriber && cont.provider == d.provider && cont.fee == d.fee && cont.interval_secs == d.interval_secs && cont.next_due == d.next_due + d.interval_secs
            }
            None -> False
          }

        interval_elapsed && provider_paid && continuing_valid
      }

      Cancel ->
        list.has(self.extra_signatories, d.subscriber)
    }
  }

  else(_) {
    False
  }
}

