pub type AuctionDatum {
  highest_bid: Int,
  bidder: ByteArray,
  deadline: Int,
}

fn find_continuing_output(outputs: List<Output>, own_address: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

fn get_own_address(inputs: List<Input>, utxo: OutputReference) -> Option<Address> {
  let found =
    list.find(inputs, fn(i) { i.output_reference == utxo })
  when found is {
    Some(input) -> Some(input.output.address)
    None -> None
  }
}

validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current_datum) = datum

    let deadline_not_passed =
      interval.is_entirely_before(self.validity_range, current_datum.deadline)

    expect Some(own_address) = get_own_address(self.inputs, utxo)

    expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

    expect InlineDatum(raw) = cont_out.datum
    expect new_datum: AuctionDatum = raw

    let bid_exceeds_current = new_datum.highest_bid > current_datum.highest_bid

    let value_covers_bid =
      assets.lovelace_of(cont_out.value) >= new_datum.highest_bid

    let deadline_preserved = new_datum.deadline == current_datum.deadline

    deadline_not_passed && bid_exceeds_current && value_covers_bid && deadline_preserved
  }

  else(_) {
    False
  }
}

