pub type Limits {
  min: Int,
  max: Int,
}

pub type VaultDatum {
  owner: ByteArray,
  limits: Limits,
}

fn total_lovelace_to_address(outputs: List<Output>, addr: Address) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      if o.address == addr {
        acc + assets.lovelace_of(o.value)
      } else {
        acc
      }
    },
  )
}

validator nested_config {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let owner_signed = list.has(self.extra_signatories, d.owner)

    let own_input_opt =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    expect Some(own_input) = own_input_opt

    let own_address = own_input.output.address

    let amount = total_lovelace_to_address(self.outputs, own_address)

    let within_limits = amount >= d.limits.min && amount <= d.limits.max

    owner_signed && within_limits
  }
}

use aiken/collection/list
