pub type StateDatum {
  state: Int,
  owner: ByteArray,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator state_machine {
  spend(
    datum: Option<StateDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current) = datum

    expect Some(own_input) = find_own_input(self.inputs, utxo)

    let own_address = own_input.output.address

    expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

    expect InlineDatum(raw) = cont_out.datum
    expect next: StateDatum = raw

    let state_incremented = next.state == current.state + 1
    let owner_preserved = next.owner == current.owner
    let signed_by_owner = list.has(self.extra_signatories, current.owner)

    state_incremented && owner_preserved && signed_by_owner
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type PoolDatum {
  reserve_a: Int,
  reserve_b: Int,
  lp_supply: Int,
}

pub type WithdrawRedeemer {
  lp_burn_amount: Int,
  lp_policy_id: ByteArray,
  lp_asset_name: ByteArray,
  token_a_policy_id: ByteArray,
  token_a_asset_name: ByteArray,
  token_b_policy_id: ByteArray,
  token_b_asset_name: ByteArray,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_input: Input) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_input.output.address })
}

fn div_floor(a: Int, b: Int) -> Int {
  a / b
}

validator lp_withdraw {
  spend(
    datum: Option<PoolDatum>,
    redeemer: WithdrawRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(pool_datum) = datum

    let lp_burn = redeemer.lp_burn_amount

    expect lp_burn > 0
    expect pool_datum.lp_supply > 0

    let expected_a = div_floor(lp_burn * pool_datum.reserve_a, pool_datum.lp_supply)
    let expected_b = div_floor(lp_burn * pool_datum.reserve_b, pool_datum.lp_supply)

    expect expected_a > 0
    expect expected_b > 0

    expect Some(own_input) = find_own_input(self.inputs, utxo)

    let mint_value = self.mint
    let lp_minted =
      assets.quantity_of(mint_value, redeemer.lp_policy_id, redeemer.lp_asset_name)

    expect lp_minted == -lp_burn

    expect Some(cont_out) = find_continuing_output(self.outputs, own_input)

    expect InlineDatum(raw) = cont_out.datum
    expect new_datum: PoolDatum = raw

    let new_reserve_a =
      assets.quantity_of(
        cont_out.value,
        redeemer.token_a_policy_id,
        redeemer.token_a_asset_name,
      )
    let new_reserve_b =
      assets.quantity_of(
        cont_out.value,
        redeemer.token_b_policy_id,
        redeemer.token_b_asset_name,
      )

    let old_reserve_a =
      assets.quantity_of(
        own_input.output.value,
        redeemer.token_a_policy_id,
        redeemer.token_a_asset_name,
      )
    let old_reserve_b =
      assets.quantity_of(
        own_input.output.value,
        redeemer.token_b_policy_id,
        redeemer.token_b_asset_name,
      )

    let withdrawn_a = old_reserve_a - new_reserve_a
    let withdrawn_b = old_reserve_b - new_reserve_b

    expect withdrawn_a >= expected_a
    expect withdrawn_b >= expected_b

    expect new_datum.reserve_a == new_reserve_a
    expect new_datum.reserve_b == new_reserve_b
    expect new_datum.lp_supply == pool_datum.lp_supply - lp_burn

    expect new_datum.reserve_a >= 0
    expect new_datum.reserve_b >= 0
    expect new_datum.lp_supply >= 0

    True
  }

  else(_) {
    False
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type LoanDatum {
  borrower: ByteArray,
  principal: Int,
  interest: Int,
  due_date: Int,
}

fn total_repayment(d: LoanDatum) -> Int {
  d.principal + d.interest
}

fn borrower_signed(self: Transaction, borrower: ByteArray) -> Bool {
  list.has(self.extra_signatories, borrower)
}

fn sufficient_repayment(self: Transaction, required: Int) -> Bool {
  list.any(
    self.outputs,
    fn(o: Output) { assets.lovelace_of(o.value) >= required },
  )
}

validator loan_repay {
  spend(
    datum: Option<LoanDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let required = total_repayment(d)
    let signed = borrower_signed(self, d.borrower)
    let before_due = interval.is_entirely_before(self.validity_range, d.due_date)
    let repaid = sufficient_repayment(self, required)
    signed && repaid && before_due
  }
}

