use aiken/collection/list
use aiken/interval
use cardano/address.{Address, VerificationKey}
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type SplitDatum {
  party_a: ByteArray,
  party_b: ByteArray,
  share_a_bps: Int,
}

fn address_of_pkh(pkh: ByteArray) -> Address {
  Address {
    payment_credential: VerificationKey(pkh),
    stake_credential: None,
  }
}

fn lovelace_to_address(outputs: List<Output>, addr: Address) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      if o.address == addr {
        acc + assets.lovelace_of(o.value)
      } else {
        acc
      }
    },
  )
}

validator reward_split {
  spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    own_input: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let total_lovelace =
      list.foldl(
        self.inputs,
        0,
        fn(i, acc) {
          if i.output_reference == own_input {
            acc + assets.lovelace_of(i.output.value)
          } else {
            acc
          }
        },
      )

    let share_a = total_lovelace * d.share_a_bps / 10000
    let share_b = total_lovelace - share_a

    let addr_a = address_of_pkh(d.party_a)
    let addr_b = address_of_pkh(d.party_b)

    let paid_a = lovelace_to_address(self.outputs, addr_a)
    let paid_b = lovelace_to_address(self.outputs, addr_b)

    paid_a >= share_a && paid_b >= share_b
  }

  else(_) {
    fail
  }
}

