}

pub type CollateralDatum {
  borrower: ByteArray,
  loan_ref: ByteArray,
  liquidation_ratio: Int,
}

pub type CollateralRedeemer {
  BorrowerWithdraw
  Liquidate { current_ratio: Int, deadline: Int }
}

validator collateral_vault {
  spend(
    datum: Option<CollateralDatum>,
    redeemer: CollateralRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      BorrowerWithdraw -> list.has(self.extra_signatories, d.borrower)

      Liquidate { current_ratio, deadline } -> {
        let borrower_signed = list.has(self.extra_signatories, d.borrower)

        let in_default =
          current_ratio < d.liquidation_ratio && interval.is_entirely_after(
            self.validity_range,
            deadline,
          )

        borrower_signed || in_default
      }
    }
  }

  else(_) {
    fail
  }
}

