use aiken/collection/list
use aiken/interval
use cardano/address.{Address}
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, NoDatum, Output, OutputReference, Transaction,
}

pub type VersionedDatum {
  version: Int,
  admin: ByteArray,
  params: Int,
}

pub type UpgradeableRedeemer {
  Use
  Upgrade { new_version: Int, new_params: Int }
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_address: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator upgradeable {
  spend(
    datum: Option<VersionedDatum>,
    redeemer: UpgradeableRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Use -> True

      Upgrade { new_version, new_params } -> {
        let is_signed_by_admin =
          list.has(self.extra_signatories, d.admin)

        let version_bumped = new_version == d.version + 1

        expect Some(own_input) = find_own_input(self.inputs, utxo)
        let own_address = own_input.output.address

        expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

        let value_preserved =
          assets.lovelace_of(cont_out.value) >= assets.lovelace_of(
            own_input.output.value,
          )

        let datum_valid =
          when cont_out.datum is {
            InlineDatum(raw) -> {
              expect next: VersionedDatum = raw
              next.version == new_version && next.admin == d.admin && next.params == new_params
            }
            _ -> False
          }

        is_signed_by_admin && version_bumped && value_preserved && datum_valid
      }
    }
  }
}

