pub type SaleDatum {
  seller: ByteArray,
  token_policy: ByteArray,
  token_name: ByteArray,
  price: Int,
}

fn address_from_pkh(pkh: ByteArray) -> Address {
  Address {
    payment_credential: address.VerificationKey(pkh),
    stake_credential: None,
  }
}

validator token_sale {
  spend(
    datum: Option<SaleDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let seller_address = address_from_pkh(d.seller)

    let seller_gets_price =
      list.any(
        self.outputs,
        fn(o: Output) {
          o.address == seller_address && assets.lovelace_of(o.value) >= d.price
        },
      )

    let buyer_gets_token =
      list.any(
        self.outputs,
        fn(o: Output) {
          assets.quantity_of(o.value, d.token_policy, d.token_name) == 1
        },
      )

    seller_gets_price && buyer_gets_token
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type FundDatum {
  goal: Int,
  deadline: Int,
  creator: ByteArray,
}

pub type FundRedeemer {
  Withdraw
  Refund
}

fn total_lovelace_in_outputs(outputs: List<Output>, addr) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      if o.address == addr {
        acc + assets.lovelace_of(o.value)
      } else {
        acc
      }
    },
  )
}

validator crowdfund {
  spend(
    datum: Option<FundDatum>,
    redeemer: FundRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Withdraw -> {
        let after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)
        let signed_by_creator =
          list.has(self.extra_signatories, d.creator)
        let inputs_lovelace =
          list.foldl(
            self.inputs,
            0,
            fn(i, acc) {
              when i.output.datum is {
                InlineDatum(raw) -> {
                  expect fund: FundDatum = raw
                  if
                  fund.creator == d.creator && fund.deadline == d.deadline && fund.goal == d.goal{
                    acc + assets.lovelace_of(i.output.value)
                  } else {
                    acc
                  }
                }
                _ -> acc
              }
            },
          )
        let goal_met = inputs_lovelace >= d.goal
        after_deadline && signed_by_creator && goal_met
      }

      Refund -> {
        let after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)
        let inputs_lovelace =
          list.foldl(
            self.inputs,
            0,
            fn(i, acc) {
              when i.output.datum is {
                InlineDatum(raw) -> {
                  expect fund: FundDatum = raw
                  if
                  fund.creator == d.creator && fund.deadline == d.deadline && fund.goal == d.goal{
                    acc + assets.lovelace_of(i.output.value)
                  } else {
                    acc
                  }
                }
                _ -> acc
              }
            },
          )
        let goal_not_met = inputs_lovelace < d.goal
        let _ = utxo
        after_deadline && goal_not_met
      }
    }
  }

  else(_) {
    fail
  }
}

