use aiken/collection/list
use cardano/address.{Address}
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type WhitelistDatum {
  whitelist: List<ByteArray>,
  price: Int,
  max_per_wallet: Int,
}

pub type WhitelistRedeemer {
  buyer: ByteArray,
  quantity: Int,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_output_to_address(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator whitelist_sale {
  spend(
    datum: Option<WhitelistDatum>,
    redeemer: WhitelistRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let buyer = redeemer.buyer
    let quantity = redeemer.quantity

    // Buyer must be in the whitelist
    let buyer_whitelisted = list.has(d.whitelist, buyer)

    // Buyer must have signed the transaction
    let buyer_signed = list.has(self.extra_signatories, buyer)

    // Quantity must be positive and within max per wallet
    let valid_quantity = quantity > 0 && quantity <= d.max_per_wallet

    // Calculate total price owed
    let total_price = d.price * quantity

    // Find own input to determine script address
    expect Some(own_input) = find_own_input(self.inputs, utxo)
    let script_address = own_input.output.address

    // Find payment output back to script (continuing output with updated state)
    // or verify payment goes to the script owner
    // Here we verify that the script receives the correct payment
    let script_receives_payment =
      list.any(
        self.outputs,
        fn(o) {
          o.address == script_address && assets.lovelace_of(o.value) >= total_price
        },
      )

    // Find any output to buyer and validate quantity constraint
    // We check that the buyer sends the required lovelace to the script
    let payment_output_exists =
      when find_output_to_address(self.outputs, script_address) is {
        Some(out) -> assets.lovelace_of(out.value) >= total_price
        None -> False
      }

    buyer_whitelisted && buyer_signed && valid_quantity && (
      script_receives_payment || payment_output_exists
    )
  }

  else(_) {
    False
  }
}

