use aiken/collection/list
use cardano/address.{Address, VerificationKey}
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type BatchDatum {
  recipients: List<ByteArray>,
  amounts: List<Int>,
  sender: ByteArray,
}

fn recipient_amount_pairs(
  recipients: List<ByteArray>,
  amounts: List<Int>,
) -> List<(ByteArray, Int)> {
  when recipients is {
    [] -> []
    [r, ..rest_r] ->
      when amounts is {
        [] -> []
        [a, ..rest_a] ->
          [(r, a), ..recipient_amount_pairs(rest_r, rest_a)]
      }
  }
}

fn output_satisfies_pair(output: Output, pair: (ByteArray, Int)) -> Bool {
  let (recipient, amount) = pair
  when output.address.payment_credential is {
    VerificationKey(pkh) ->
      pkh == recipient && assets.lovelace_of(output.value) >= amount
    _ -> False
  }
}

fn pair_has_matching_output(
  pair: (ByteArray, Int),
  outputs: List<Output>,
) -> Bool {
  list.any(outputs, fn(o) { output_satisfies_pair(o, pair) })
}

fn all_pairs_satisfied(
  pairs: List<(ByteArray, Int)>,
  outputs: List<Output>,
) -> Bool {
  list.all(pairs, fn(pair) { pair_has_matching_output(pair, outputs) })
}

validator batch_transfer {
  spend(
    datum: Option<BatchDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let sender_signed = list.has(self.extra_signatories, d.sender)
    let pairs = recipient_amount_pairs(d.recipients, d.amounts)
    let has_at_least_one_pair = !list.is_empty(pairs)
    let all_satisfied = all_pairs_satisfied(pairs, self.outputs)
    sender_signed && has_at_least_one_pair && all_satisfied
  }

  else(_) {
    fail
  }
}

