use aiken/collection/list
use aiken/interval
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type EscrowDatum {
  beneficiary: ByteArray,
  deadline: Int,
  refund_to: ByteArray,
}

validator escrow_timeout {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let beneficiary_signed =
      list.has(self.extra_signatories, d.beneficiary)

    let owner_signed =
      list.has(self.extra_signatories, d.refund_to)

    let before_deadline =
      interval.is_entirely_before(self.validity_range, d.deadline)

    let after_deadline =
      interval.is_entirely_after(self.validity_range, d.deadline)

    let release_valid = beneficiary_signed && before_deadline

    let refund_valid = after_deadline && owner_signed

    release_valid || refund_valid
  }
