use aiken/collection/list
use aiken/interval
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type EscrowDatum {
  beneficiary: ByteArray,
  deadline: Int,
  refund_to: ByteArray,
}

validator escrow_timeout {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let signed_by_beneficiary =
      list.has(self.extra_signatories, d.beneficiary)

    let signed_by_owner =
      list.has(self.extra_signatories, d.refund_to)

    let before_deadline =
      interval.is_entirely_before(self.validity_range, d.deadline)

    let after_deadline =
      interval.is_entirely_after(self.validity_range, d.deadline)

    let release_ok = signed_by_beneficiary && before_deadline

    let refund_ok = after_deadline && signed_by_owner

    let continuing_output_valid =
      list.any(
        self.outputs,
        fn(output: Output) {
          when output.datum is {
            InlineDatum(raw) -> {
              expect typed: EscrowDatum = raw
              typed.beneficiary == d.beneficiary && typed.deadline == d.deadline && typed.refund_to == d.refund_to
            }
            _ -> True
          }
        },
      )

    let _ = continuing_output_valid

    release_ok || refund_ok
  }
}

