  bidder: ByteArray,
  deadline: Int,
}

fn find_continuing_output(outputs: List<Output>, own_address: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

fn get_own_address(inputs: List<Input>, utxo: OutputReference) -> Option<Address> {
  let found =
    list.find(inputs, fn(i) { i.output_reference == utxo })
  when found is {
    Some(input) -> Some(input.output.address)
    None -> None
  }
}

validator auction_bid {
  spend(
    datum: Option<AuctionDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current) = datum

    expect False == interval.is_entirely_after(self.validity_range, current.deadline)

    expect Some(own_address) = get_own_address(self.inputs, utxo)

    expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

    when cont_out.datum is {
      InlineDatum(raw) -> {
        expect new_datum: AuctionDatum = raw

        let bid_increases = new_datum.highest_bid > current.highest_bid

        let deadline_unchanged = new_datum.deadline == current.deadline

        let new_bid_value = assets.lovelace_of(cont_out.value)

        let value_matches = new_bid_value >= new_datum.highest_bid

        bid_increases && deadline_unchanged && value_matches
      }
      _ -> False
    }
  }
}

