  limits: Limits,
}

fn total_output_lovelace(outputs: List<Output>, owner: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(output, acc) {
      when output.datum is {
        InlineDatum(raw) -> {
          expect d: VaultDatum = raw
          if d.owner == owner {
            acc + assets.lovelace_of(output.value)
          } else {
            acc
          }
        }
        _ -> acc
      }
    },
  )
}

validator nested_config {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let amount = total_output_lovelace(self.outputs, d.owner)
    let within_limits = amount >= d.limits.min && amount <= d.limits.max
    let signed_by_owner = list.has(self.extra_signatories, d.owner)
    signed_by_owner && within_limits
  }

  else(_) {
    fail
  }
}

