pub type SplitDatum {
  party_a: ByteArray,
  party_b: ByteArray,
  share_a_bps: Int,
}

fn sum_lovelace_to_pkh(outputs: List<Output>, pkh: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      when o.address.payment_credential is {
        VerificationKey(k) ->
          if k == pkh {
            acc + assets.lovelace_of(o.value)
          } else {
            acc
          }
        _ -> acc
      }
    },
  )
}

validator reward_split {
  spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    // Validate share_a_bps is in valid range [0, 10000]
    let valid_bps = d.share_a_bps >= 0 && d.share_a_bps <= 10000

    // Find own input to get total locked value
    let total_input_lovelace =
      list.foldl(
        self.inputs,
        0,
        fn(inp, acc) {
          acc + assets.lovelace_of(inp.output.value)
        },
      )

    // Calculate expected shares
    let expected_a = total_input_lovelace * d.share_a_bps / 10000
    let expected_b = total_input_lovelace * (10000 - d.share_a_bps) / 10000

    // Sum actual lovelace sent to each party
    let actual_a = sum_lovelace_to_pkh(self.outputs, d.party_a)
    let actual_b = sum_lovelace_to_pkh(self.outputs, d.party_b)

    valid_bps && actual_a >= expected_a && actual_b >= expected_b
  }

  else(_) {
    False
  }
}

