fn find_reference_nonce_datum(
  reference_inputs: List<Input>,
) -> Option<NonceDatum> {
  let result =
    list.find(
      reference_inputs,
      fn(input) {
        when input.output.datum is {
          InlineDatum(raw) -> {
            expect _nd: NonceDatum = raw
            True
          }
          _ -> False
        }
      },
    )
  when result is {
    Some(input) ->
      when input.output.datum is {
        InlineDatum(raw) -> {
          expect nd: NonceDatum = raw
          Some(nd)
        }
        _ -> None
      }
    None -> None
  }
}

fn nonce_not_used(nonce_datum: NonceDatum, nonce: ByteArray) -> Bool {
  !list.has(nonce_datum.used_nonces, nonce)
}

fn recipient_receives_amount(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      when output.address.payment_credential is {
        address.VerificationKey(pkh) ->
          pkh == recipient && assets.lovelace_of(output.value) >= amount
        _ -> False
      }
    },
  )
}

validator bridge_release {
  spend(
    datum: Option<BridgeDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let nonce_datum_opt = find_reference_nonce_datum(self.reference_inputs)

    expect Some(nonce_datum) = nonce_datum_opt

    let nonce_unused = nonce_not_used(nonce_datum, d.nonce)

    let recipient_paid =
      recipient_receives_amount(self.outputs, d.recipient, d.amount)

    nonce_unused && recipient_paid
  }
}

