  InlineDatum, Input, NoDatum, Output, OutputReference, Transaction,
}

pub type VersionedDatum {
  version: Int,
  admin: ByteArray,
  params: Int,
}

pub type UpgradeRedeemer {
  Use
  Upgrade { new_version: Int, new_params: Int }
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator upgradeable {
  spend(
    datum: Option<VersionedDatum>,
    redeemer: UpgradeRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Use -> True

      Upgrade { new_version, new_params } -> {
        let is_signed_by_admin =
          list.has(self.extra_signatories, d.admin)

        let is_version_bumped = new_version > d.version

        expect Some(own_input) = find_own_input(self.inputs, utxo)
        let own_address = own_input.output.address

        expect Some(cont_out) =
          find_continuing_output(self.outputs, own_address)

        let datum_ok =
          when cont_out.datum is {
            InlineDatum(raw) -> {
              expect new_datum: VersionedDatum = raw
              new_datum.version == new_version && new_datum.admin == d.admin && new_datum.params == new_params
            }
            _ -> False
          }

        let value_preserved =
          assets.lovelace_of(cont_out.value) >= assets.lovelace_of(
            own_input.output.value,
          )

        is_signed_by_admin && is_version_bumped && datum_ok && value_preserved
      }
    }
  }
}

