    fn(o) {
      when o.address.payment_credential is {
        address.VerificationKey(pkh) ->
          pkh == seller_addr_payment && assets.lovelace_of(o.value) >= price
        _ -> False
      }
    },
  )
}

fn buyer_receives_token(
  outputs: List<Output>,
  seller: ByteArray,
  token_policy: ByteArray,
  token_name: ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        address.VerificationKey(pkh) -> {
          let not_seller = pkh != seller
          let has_token =
            assets.quantity_of(o.value, token_policy, token_name) == 1
          not_seller && has_token
        }
        address.Script(_) -> {
          assets.quantity_of(o.value, token_policy, token_name) == 1
        }
      }
    },
  )
}

validator token_sale {
  spend(
    datum: Option<SaleDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let seller_paid =
      seller_receives_price(self.outputs, d.seller, d.price)
    let buyer_got_token =
      buyer_receives_token(
        self.outputs,
        d.seller,
        d.token_policy,
        d.token_name,
      )
    seller_paid && buyer_got_token
  }
}

