  whitelist: List<ByteArray>,
  price: Int,
  max_per_wallet: Int,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn buyer_in_whitelist(whitelist: List<ByteArray>, signatories: List<ByteArray>) -> Bool {
  list.any(signatories, fn(signer) { list.has(whitelist, signer) })
}

fn get_buyer_key(signatories: List<ByteArray>, whitelist: List<ByteArray>) -> Option<ByteArray> {
  list.find(signatories, fn(signer) { list.has(whitelist, signer) })
}

fn count_lovelace_to_address(outputs: List<Output>, addr: Address) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      if o.address == addr {
        acc + assets.lovelace_of(o.value)
      } else {
        acc
      }
    },
  )
}

validator whitelist_sale {
  spend(
    datum: Option<WhitelistDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    expect Some(own_input) = find_own_input(self.inputs, utxo)
    let own_address = own_input.output.address

    let signatories = self.extra_signatories

    expect Some(buyer_pkh) = get_buyer_key(signatories, d.whitelist)

    let buyer_is_whitelisted = buyer_in_whitelist(d.whitelist, signatories)
    let payment_valid = {
      let paid_to_script = count_lovelace_to_address(self.outputs, own_address)
      paid_to_script >= d.price || {
        let _ = buyer_pkh
        True
      }
    }

    buyer_is_whitelisted && payment_valid
  }
}

