use aiken/interval
use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}
use cardano/address.{Address}

pub type RecurringDatum {
  payer: ByteArray,
  payee: ByteArray,
  amount: Int,
  period_secs: Int,
  last_paid: Int,
}

pub type RecurringRedeemer {
  Pay
  Cancel
}

fn find_output_with_datum(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator recurring_payment {
  spend(
    datum: Option<RecurringDatum>,
    redeemer: RecurringRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Pay -> {
        let deadline = d.last_paid + d.period_secs

        let period_elapsed =
          interval.is_entirely_after(self.validity_range, deadline)

        let payee_receives =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                address.VerificationKey(pkh) ->
                  pkh == d.payee && assets.lovelace_of(o.value) >= d.amount
                _ -> False
              }
            },
          )

        let own_input =
          list.find(self.inputs, fn(i) { i.output_reference == utxo })

        let continuing_output =
          when own_input is {
            Some(inp) ->
              find_output_with_datum(self.outputs, inp.output.address)
            None -> None
          }

        let datum_updated =
          when continuing_output is {
            Some(cont_out) ->
              when cont_out.datum is {
                InlineDatum(raw) -> {
                  expect cont: RecurringDatum = raw
                  cont.payer == d.payer && cont.payee == d.payee && cont.amount == d.amount && cont.period_secs == d.period_secs && cont.last_paid > d.last_paid
                }
                _ -> False
              }
            None -> False
          }

        period_elapsed && payee_receives && datum_updated
      }

      Cancel ->
        list.has(self.extra_signatories, d.payer)
    }
  }
}

