pub type OracleDatum {
  price: Int,
  timestamp: Int,
  source: ByteArray,
}

pub type SpendDatum {
  min_price: Int,
  oracle_policy_id: ByteArray,
  oracle_asset_name: ByteArray,
  owner: ByteArray,
}

pub type ConsumerRedeemer {
  oracle_ref_input_index: Int,
}

fn find_oracle_datum(
  reference_inputs: List<Input>,
  oracle_policy_id: ByteArray,
  oracle_asset_name: ByteArray,
) -> Option<OracleDatum> {
  let oracle_input =
    list.find(
      reference_inputs,
      fn(input) {
        assets.quantity_of(
          input.output.value,
          oracle_policy_id,
          oracle_asset_name,
        ) > 0
      },
    )
  when oracle_input is {
    Some(inp) ->
      when inp.output.datum is {
        InlineDatum(raw) -> {
          expect typed: OracleDatum = raw
          Some(typed)
        }
        _ -> None
      }
    None -> None
  }
}

validator oracle_consumer {
  spend(
    datum: Option<SpendDatum>,
    redeemer: ConsumerRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let oracle_datum =
      find_oracle_datum(
        self.reference_inputs,
        d.oracle_policy_id,
        d.oracle_asset_name,
      )

    when oracle_datum is {
      Some(oracle) -> {
        let price_check = oracle.price >= d.min_price
        let owner_signed = list.has(self.extra_signatories, d.owner)
        price_check && owner_signed
      }
      None -> False
    }
  }
}

