pub type Limits {
  min: Int,
  max: Int,
}

pub type VaultDatum {
  owner: ByteArray,
  limits: Limits,
}

fn total_lovelace_to_address(outputs: List<Output>, addr) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      if o.address == addr {
        acc + assets.lovelace_of(o.value)
      } else {
        acc
      }
    },
  )
}

