    expect Some(d) = datum

    let owner_signed = list.has(self.extra_signatories, d.owner)

    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    let own_address = own_input.output.address

    let amount = total_lovelace_to_address(self.outputs, own_address)

    let within_limits = amount >= d.limits.min && amount <= d.limits.max

    owner_signed && within_limits
  }
}

use aiken/collection/list
use cardano/address.{Address}
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type StateDatum {
  state: Int,
  owner: ByteArray,
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_address: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator state_machine {
  spend(
    datum: Option<StateDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(current) = datum

    expect Some(own_input) = find_own_input(self.inputs, utxo)

    let own_address = own_input.output.address

    expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

    expect InlineDatum(raw) = cont_out.datum
    expect next: StateDatum = raw

    let state_incremented = next.state == current.state + 1
    let owner_preserved = next.owner == current.owner
    let signed_by_owner = list.has(self.extra_signatories, current.owner)

    state_incremented && owner_preserved && signed_by_owner
  }
}
